const _authoritative_vestments = {title: "Authoritative vestments", jsx: <><h2 id="eq-misc-authoritative_vestments-authoritative-vestments">Authoritative vestments</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory">Adventurer's Armory pg. 24</Link><br/><strong>Price</strong> 450 gp; <strong>Weight</strong> 15 lbs.<br/><strong>Category</strong> Channel Foci<br/><strong>Deity</strong> Any</p>
<p>Typically worn by senior members of a faith, these cumbersome but splendidly ornate garments create an aura of dignity and gravitas that few dare to challenge. When activated, the garments make you seem more impressive and worthy of respect to all viewers within 60 feet of you; you may make a single Diplomacy check to change the attitudes of these viewers as a swift action. You can only use this ability on a particular viewer once per day (additional attempts have no effect, though you can still persuade viewers normally without the help of the focus).</p>
</>};
const _automatic_writing_planchette = {title: "Automatic writing planchette", jsx: <><h2 id="eq-misc-automatic_writing_planchette-automatic-writing-planchette">Automatic writing planchette</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 248</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>This finely crafted, heart-shaped wooden board has two delicate wheels and a small aperture to hold a pencil, which acts as the board's third leg. Typically used on a tabletop covered in butcher's paper, the device scribbles out mysterious messages when employed by a creature using the <Link to="/skill/automatic_writing">automatic writing</Link> occult skill unlock, and provides a +2 circumstance bonus on the Linguistics check. When used to channel certain haunts capable of communication, the planchette doubles the rate of communication with the haunt, and grants the user a +4 circumstance bonus on Linguistics checks to decipher the cryptic messages. These benefits do not stack with those of other items that confer similar benefits (such as a <Link to="/eq-misc/talking_board">talking board</Link>).</p>
</>};
const _autosniper_trap = {title: "Autosniper trap", jsx: <><h2 id="eq-misc-autosniper_trap-autosniper-trap">Autosniper trap</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 20</Link><br/><strong>Price</strong> 250 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This framework consists of a small tripod, a spool of wire, and a series of levels. As part of the action to set up the trap, the autosniper is attached to any Small or Medium crossbow and its wire strung across one or two 5-foot squares within 10 feet. Once set, the autosniper fires the attached crossbow automatically at the first Tiny or larger creature that disturbs its tripwire. An autosniper cannot reload the crossbow to which it is attached.</p>
<p>The general bulkiness of an autosniper's framework imposes a -2 penalty on any attempts to use its attached crossbow as a ranged weapon. An autosniper can be removed from a crossbow with 1 minute of work.</p>
<p>This can be crafted with a DC 25 Craft (traps) check.</p>
<p><strong>Autosniper Trap</strong><br/><strong>Type</strong> mechanical; <strong>Perception</strong> DC 15; <strong>Disable Device</strong> DC 15<br/><strong>Effects</strong><br/><strong>Trigger</strong> touch; <strong>Reset</strong> manual<br/><strong>Effect</strong> Atk +5 ranged (damage varies by crossbow)</p>
</>};
const _axe_beak_combat_trained = {title: "Axe beak (combat trained)", jsx: <><h2 id="eq-misc-axe_beak_combat_trained-axe-beak-combat-trained">Axe beak (combat trained)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 81</Link><br/><strong>Price</strong> 1,500 gp; <strong>Weight</strong> 500 lbs.<br/><strong>Category</strong> Mounts/Pets</p>
<p>These Large avian predators are sometimes used as hunting animals but are prized as mounts.</p>
</>};
const _axe_beak_egg = {title: "Axe beak egg", jsx: <><h2 id="eq-misc-axe_beak_egg-axe-beak-egg">Axe beak egg</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 81</Link><br/><strong>Price</strong> 1,000 gp; <strong>Weight</strong> 10 lbs.<br/><strong>Category</strong> Mounts/Pets</p>
<p>Axe beaks raised from eggs are easily trained as mounts or used as livestock.</p>
</>};
const _bachelor_snuff = {title: "Bachelor snuff", jsx: <><h2 id="eq-misc-bachelor_snuff-bachelor-snuff">Bachelor snuff</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Black Market</p>
<p>If inhaled through the nose, this sooty-smelling golden powder renders humanoid males temporarily sterile without otherwise affecting their performance. A dose typically lasts 1-3 days. Long-term users of bachelor snuff tend to develop a slight, but still noticeable, gilded tinge to their teeth and nails.</p>
</>};
const _backpack_common = {title: "Backpack (common)", jsx: <><h2 id="eq-misc-backpack_common-backpack">Backpack</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 25 gp (carrier), 2 gp (common), 40 gp (hydration), 50 gp (masterwork), 25 gp (weaponrack); <strong>Weight</strong> 5 lbs. (carrier), 2 lbs. (common), 4 lbs. (hydration), 4 lbs. (masterwork), 5 lbs. (weaponrack)</p>
<p>This leather knapsack has one large pocket that closes with a buckled strap and holds about 2 cubic feet of material. Some may have one or more smaller pockets on the sides.</p>
<p><strong>Masterwork Backpack:</strong> This backpack has numerous pockets for storing items that might be needed while adventuring. Hooks are included for attaching items such as canteens, pouches, or even a rolled-up blanket. It has padded bands that strap across the chest and the waist to distribute its weight more evenly. Like a common backpack, it can hold about 2 cubic feet of material in its main container. When wearing a masterwork backpack, treat your Strength score as +1 higher than normal when calculating your <Link to="/rule/carrying_capacity">carrying capacity</Link>.</p>
<p><strong>Carrier Backpack:</strong> Reinforced metal bars allow for this leather backpack to withstand a greater degree of stress than a traditional pack. Along with the standard backpack compartment, this pack has an additional pouch and harness at its top. Used together, the harness and pouch can safely contain a Tiny or smaller creature. While harnessed, the creature can't leave the backpack or see outside of it; it takes a full-round action to remove the harness from a carried creature.</p>
<p><strong>Hydration Backpack:</strong> This mostly leather backpack has a series of awkward metallic tubes, which run from the pack over your shoulders, and a small bladder at its base. A hydration backpack has a large pocket identical to that of a regular backpack that holds 2 cubic feet of material, while the bladder holds 1 gallon of liquid. The ends of the metal tubes can be positioned to allow you to easily dispense and drink liquid stored in the attached bladder. Consuming water in this way grants a +2 circumstance bonus on Constitution checks to avoid nonlethal damage during a forced march.</p>
<p><strong>Weaponrack Backpack:</strong> This leather backpack includes a small weapons rack. The rack holds up to four weapons, such as battleaxes, longswords, maces, or short swords. Allies adjacent to you can retrieve a weapon from the rack as a move action without provoking attacks of opportunity, as if they were simply drawing a weapon. Like a normal backpack, it can hold 2 cubic feet of material in its main compartment.</p>
</>};
const _badger_plush = {title: "Badger plush", jsx: <><h2 id="eq-misc-badger_plush-badger-plush">Badger plush</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 4</Link><br/><strong>Price</strong> 45 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This stuffed badger - a well-loved and legally protected animal in Absalom - is realistic enough to fool most other animals into thinking it is real. As a move action, a wielder can use a free hand to present the plush; any Small or smaller animal with an Intelligence score of 1 or 2 that can see it takes a -2 penalty on initiative checks.</p>
</>};
const _badger = {title: "Badger", jsx: <><h2 id="eq-misc-badger-badger">Badger</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 80</Link><br/><strong>Price</strong> 15 gp; <strong>Weight</strong> 20 lbs.<br/><strong>Category</strong> Mounts/Pets</p>
<p>These fierce, burrowing creatures are only rarely kept as pets.</p>
</>};
const _bag_bear = {title: "Bag, bear", jsx: <><h2 id="eq-misc-bag_bear-bag-bear">Bag, bear</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 27</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 3 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>These sacks each include a 20-foot-long rope, from which they may be easily suspended from a tree limb or similar anchor point. Placing foodstuffs or fragile materials in hanging sacks is often considered a basic precaution when camping in the wild, to prevent bears and other predators from rooting through the sack's contents.</p>
</>};
const _baijiu_bottle = {title: "Baijiu (bottle)", jsx: <><h2 id="eq-misc-baijiu_bottle-baijiu-bottle">Baijiu (bottle)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 95</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Food/Drink</p>
<p>This clear alcoholic beverage, distilled from sorghum, is extremely potent, and is often regarded as an acquired taste due to its corrosive flavor.</p>
</>};
const _balancing_pole = {title: "Balancing pole", jsx: <><h2 id="eq-misc-balancing_pole-balancing-pole">Balancing pole</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 77</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 184</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 8 sp; <strong>Weight</strong> 12 lbs.<br/><strong>Category</strong> Tools</p>
<p>This flexible pole can be anywhere from 15 to 30 feet in length. When used properly, it helps you keep your balance when crossing narrow walkways. Using a balancing pole grants you a +1 circumstance bonus on Acrobatics checks made to traverse a narrow surface.</p>
</>};
const _ball_10_in = {title: "Ball (10 in.)", jsx: <><h2 id="eq-misc-ball_10_in-ball">Ball</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 92</Link><br/><strong>Price</strong> 6 gp (10 in.), 8 cp (2 in.), 2 sp (5 in.); <strong>Weight</strong> 1 lb. (10 in.), - (2 in.), - (5 in.)</p>
<p>This ball may be an inflated animal bladder, carved from light wood, fabric stuffed with cloth or plant fiber and sewn shut.</p>
</>};
const _balloon_trap = {title: "Balloon trap", jsx: <><h2 id="eq-misc-balloon_trap-balloon-trap">Balloon trap</h2>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook pg. 26</Link><br/><strong>Price</strong> 150 gp; <strong>Weight</strong> 4 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This trap consists of a buoyant balloon tied to an anchor by a very thin strand of metal. The strand acts as a vertical tripwire that triggers the trap, targeting any flying creature that contacts it. The trap's creator may set any number of mechanical or magical effects to be triggered when the trap is activated. Balloon traps are especially useful against creatures with large wingspans, or when the balloon is concealed, as in a tree canopy or smoke cover. Below is a sample balloon trap.</p>
<p><strong>Sirocco Balloon Trap - CR 14</strong><br/><strong>Type</strong> magic; <strong>Perception</strong> DC 31; <strong>Disable Device</strong> DC 31<br/><strong>Effects</strong><br/><strong>Trigger</strong> touch; <strong>Reset</strong> none<br/><strong>Effect</strong> spell effect (<Link to="/spell/sirocco">sirocco</Link>, 4d6+11 fire damage [DC 19 Fort for half] plus <Link to="/misc/fatigued">fatigued</Link>, knocked <Link to="/rule/prone">prone</Link> [DC 19 Fort avoids], flying creatures grounded [DC 15 Fly avoids]); multiple targets (all creatures in a 20-ft.-radius, 60-ft.-high cylinder centered on the balloon trap tripwire)</p>
</>};
const _bamboo_palace = {title: "Bamboo palace", jsx: <><h2 id="eq-misc-bamboo_palace-bamboo-palace">Bamboo palace</h2>
<p><strong>Sources</strong> <Link to="/source/lost_treasures">Lost Treasures pg. 18</Link><br/><strong>Price</strong> 1,000 gp; <strong>Weight</strong> 10 lbs.<br/><strong>Category</strong> Black Market</p>
<p>The Bamboo Palace is a bonsai group planting of bamboo that has been shaped to resemble Hwanggot's royal palace in Haseoung. The bonsai is nonmagical, but in its pristine state is a magnificent representation of the art of bonsai. Though the planting is regrettably overgrown, the frame of a brilliant bonsai is still visible to those familiar with the art form. Beneath the shaggy foliage, one can see that the stems part and interweave again to form windows and doors, and the side branches gracefully curve out to mimic tiered roofs. The bonsai sits in a graceful celadon-glazed pot engraved with the seal of the Yeon dynasty.</p>
<p>The Bamboo Palace's price reflects its current neglected state mixed with its aesthetic potential. If an experienced bonsai gardener tends to it once a week for 1 year, the Bamboo Palace reassumes its earlier manicured form, and its value to a collector increases to 8,000 gp. Restoring it requires successful DC 15 Knowledge (nature) and Knowledge (engineering) checks each week during that time.</p>
<p>If the Bamboo Palace is restored to its full glory, a character who spends 15 minutes tending to it and succeeds at DC 20 Knowledge (nature) and Knowledge (engineering) checks gains the favor of Upaskuma, the fukujin kami who lives within the bonsai. For 24 hours, whenever the favored character begins a round within 15 feet of the Bamboo Palace, the kami's aura of luck grants the character a +2 luck bonus on all skill checks. Only one character can gain this favor each day.</p>
</>};
const _bandolier = {title: "Bandolier", jsx: <><h2 id="eq-misc-bandolier-bandolier">Bandolier</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 5 sp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>This leather belt is worn over one shoulder and runs diagonally across the chest and back. It has small loops or pouches for holding eight objects the size of a flask or small dagger. You can use the "retrieve a stored item" action to take an item from a bandolier. You can wear up to two bandoliers at the same time (any more than this and they get in each other's way and restrict your movement).</p>
</>};
const _banner = {title: "Banner", jsx: <><h2 id="eq-misc-banner-banner">Banner</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 1-20 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This is a banner, flag, or pennant. You tie it to a pole, lance, or polearm. Most are woven, dyed, or painted with a pattern or symbol, such as a knight's crest or a country's flag. A simple banner with one field color and a simple insignia such as a weapon or shield costs 1 gp. A banner with two to four field colors and a complex insignia such as a lion or dragon costs 5 gp. A detailed banner with four or more field colors and a very complex insignia, such as a heraldic device with eight or more sections, costs 20 gp.</p>
</>};
const _banquet_per_person = {title: "Banquet (per person)", jsx: <><h2 id="eq-misc-banquet_per_person-banquet-per-person">Banquet (per person)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 95</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 159</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Food/Drink</p>
<p>A banquet includes several food courses, good drinks, and servants to bring the food and take away empty plates. The listed price is for having a banquet at a restaurant (though some restaurant owners can be hired to serve a banquet at a private location). The price listed above is per person.</p>
</>};
const _barbarian_chew = {title: "Barbarian chew", jsx: <><h2 id="eq-misc-barbarian_chew-barbarian-chew">Barbarian chew</h2>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends pg. 15</Link>, <Link to="/source/curse_of_the_crimson_throne_players_guide">Curse of the Crimson Throne Player's Guide pg. 12</Link>, <Link to="/source/rise_of_the_runelords_players_guide">Rise of the Runelords Player's Guide pg. 11</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>The Shoanti of the Cinderlands combine lime, crimson galtroot leaves, and some say horse blood to create this invigorating chew. Aside from staining the teeth a bloody shade, barbarian chew causes the user to feel stronger, but also angrier. One use of barbarian chew grants a barbarian +1 additional round of rage. This additional round is used first when a barbarian begins raging. If a barbarian does not rage within 1 hour of using the chew, this additional round of rage is lost. This benefit can be gained only once per day; consuming multiple doses in a 24-hour period has no additional effects. Barbarian chew can be created with a successful DC 20 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _barbarians_kit = {title: "Barbarian's kit", jsx: <><h2 id="eq-misc-barbarians_kit-barbarians-kit">Barbarian's kit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 9 gp; <strong>Weight</strong> 26 lbs.<br/><strong>Category</strong> Kits</p>
<p>This kit includes a <Link to="/eq-misc/backpack">backpack</Link>, a <Link to="/eq-misc/belt_pouch">belt pouch</Link>, a <Link to="/eq-misc/blanket">blanket</Link>, a <Link to="/eq-misc/flint_and_steel">flint and steel</Link>, an <Link to="/eq-misc/iron_pot">iron pot</Link>, <Link to="/eq-misc/rope">rope</Link>, <Link to="/eq-misc/soap">soap</Link>, <Link to="/eq-misc/torches">torches</Link> (10), <Link to="/eq-misc/trail_rations">trail rations</Link> (5 days), and a <Link to="/eq-misc/waterskin">waterskin</Link>.</p>
</>};
const _barbed_troll_claws = {title: "Barbed troll claws", jsx: <><h2 id="eq-misc-barbed_troll_claws-barbed-troll-claws">Barbed troll claws</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 225</Link><br/><strong>Price</strong> 20 gp; <strong>Weight</strong> 4 lbs.<br/><strong>Category</strong> Tools</p>
<p>These metal sheaths slide onto the claws of a <Link to="/family/troll">troll</Link>. When a troll hits with a claw attack while wearing the sheaths, it can either keep the sheaths on its hand (in which case the claw attack deals 1 extra point of damage) or allow the four sheaths on that hand to slide off and become embedded in the wound (in which case the claw attack deals 1 point of <Link to="/rule/bleed">bleed</Link> damage). The listed price is for a set of 8 sheaths (one for each claw on both of a troll's four-fingered hands).</p>
</>};
const _barbed_vest = {title: "Barbed vest", jsx: <><h2 id="eq-misc-barbed_vest-barbed-vest">Barbed vest</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 181</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> 4 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>Thin leather flaps keep the hundreds of tiny, fishhook-like needles dotting the surface of this black vest from harming you while you wear it. However, any creature that injures you with a natural or unarmed attack must make a DC 15 Reflex save or take 1 point of damage. If a creature swallows you, it takes 1 point of damage each round until it either spits you up, you escape, or you die (at which point the vest has sustained enough damage that it no longer serves as a threat). The vest can only be worn over light armor or no armor.</p>
</>};
const _bards_kit = {title: "Bard's kit", jsx: <><h2 id="eq-misc-bards_kit-bards-kit">Bard's kit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 41 gp; <strong>Weight</strong> 33-1/2 lbs.<br/><strong>Category</strong> Kits</p>
<p>This includes a <Link to="/eq-misc/backpack">backpack</Link>, a <Link to="/eq-misc/bedroll">bedroll</Link>, a <Link to="/eq-misc/belt_pouch">belt pouch</Link>, a common <Link to="/eq-misc/musical_instrument">musical instrument</Link>, a <Link to="/eq-misc/flint_and_steel">flint and steel</Link>, <Link to="/eq-misc/ink">ink</Link>, an <Link to="/eq-misc/inkpen">inkpen</Link>, an <Link to="/eq-misc/iron_pot">iron pot</Link>, a <Link to="/eq-misc/journal">journal</Link>, a <Link to="/eq-misc/mess_kit">mess kit</Link>, a <Link to="/eq-misc/mirror">mirror</Link>, <Link to="/eq-misc/rope">rope</Link>, <Link to="/eq-misc/soap">soap</Link>, <Link to="/eq-misc/torches">torches</Link> (10), <Link to="/eq-misc/trail_rations">trail rations</Link> (5 days), and a <Link to="/eq-misc/waterskin">waterskin</Link>.</p>
</>};
const _barding_stitches = {title: "Barding stitches", jsx: <><h2 id="eq-misc-barding_stitches-barding-stitches">Barding stitches</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 12</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Animal Gear</p>
<p>This thin, specially treated wire can be used to attach barding to creatures whose body types cannot normally accommodate armor, such as piscine, serpentine, and verminous animals, by delicately and thoroughly sewing the equipment directly to the creature's flesh. Equipping a creature with barding using barding stitches takes 10 times as long as the figures given in <Link to="/rule/getting_into_and_out_of_armor">Getting Into and Out of Armor</Link>, and a successful DC 25 Heal check is required to attach or remove the stitches. The creature must be helpless or willing to be equipped with barding stitches, and must have at least a +1 natural armor bonus to AC. An armored creature with barding stitches takes a -2 penalty on Strength- and Dexterity-based skill checks (in addition to any penalties from the barding itself), Fortitude and Reflex saves, and saves against effects with the pain descriptor (these penalties stack). These penalties persist for as long as the creature is equipped with barding stitches.</p>
</>};
const _barrel = {title: "Barrel", jsx: <><h2 id="eq-misc-barrel-barrel">Barrel</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 30 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This is a sturdy wooden barrel with a tight-fitting lid, banded with metal.</p>
</>};
const _basket = {title: "Basket", jsx: <><h2 id="eq-misc-basket-basket">Basket</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 4 sp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This large basket has a lid and holds about 2 cubic feet.</p>
</>};
const _bat = {title: "Bat", jsx: <><h2 id="eq-misc-bat-bat">Bat</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 80</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 5 gp, 50 gp (Uskwood); <strong>Weight</strong> 1 lb., 2 lbs. (Uskwood)</p>
<p>These Diminutive rodents are nocturnal fliers that eat insects and fruit. They rely primarily on sound to navigate rather than sight. They can be found all over Golarion and are absent only in desert and arctic regions. Some cultures keep bat houses near towns and villages to control insect problems. Bats from the Uskwood in Nidal are noted for their matte black fur and large size.</p>
</>};
const _bath_hot = {title: "Bath (hot)", jsx: <><h2 id="eq-misc-bath_hot-bath">Bath</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 99</Link><br/><strong>Price</strong> 2 cp (cold), 6 cp (hot), 2 sp-1 gp (public); <strong>Weight</strong> - (cold, hot, public)<br/><strong>Category</strong> Lodging/Services</p>
<p>A cold bath usually involves someone else's used soapy bath water. A hot bath is a one-person washtub filled with hot water one pot at a time. A public bath is a bath facility (such as a bath house or resort) that provides hot water, soap, and cologne or perfume, and may also offer wading pools, massages, or other services for an additional cost. Some public baths require membership or a minimum social status.</p>
</>};
const _battle_mask = {title: "Battle mask", jsx: <><h2 id="eq-misc-battle_mask-battle-mask">Battle mask</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 141</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Clothing</p>
<p>Made from wood, bone, or similar materials, this mask covers its wearer's actual appearance and identity by depicting a hateful, leering face instead. Because of a battle mask's excellent craftsmanship and exquisite details, the wearer gains a +1 bonus on Intimidate checks made to demoralize an opponent.</p>
</>};
const _bear_trap_offset = {title: "Bear trap (offset)", jsx: <><h2 id="eq-misc-bear_trap_offset-bear-trap">Bear Trap</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 16</Link><br/><strong>Price</strong> 3 gp Bear trap (offset), 1,800 gp Bear trap (sawtooth); <strong>Weight</strong> 10 lbs. Bear trap (offset), 20 lbs. Bear trap (sawtooth)</p>
<p>An <strong>offset</strong> bear trap is a specialized variety of a bear trap constructed with offset jaws coated in resin. It inflicts less damage on captured creatures but holds them more securely, and is therefore primarily used by trappers or bounty hunters who do not want to risk killing their prey. Offset bear traps are almost always secured to the ground by a heavy spike and chain so the captured creature can't wander far.</p>
<p>A <strong>sawtooth</strong> bear trap has vicious jaws and tighter springs. Used primarily against humanoids or monsters rather than animals, sawtooth bear traps are often painted in camouflaged colors to blend in with the trap site. Most include locking plates over the spring mechanisms to prevent tampering by intelligent victims.</p>
<blockquote>
<p><strong>Offset Bear Trap - CR 1/2</strong><br/><strong>Type</strong> mechanical; <strong>Perception</strong> DC 15; <strong>Disable Device</strong> DC 20<br/><strong>Effects</strong><br/><strong>Trigger</strong> location; <strong>Reset</strong> manual<br/><strong>Effect</strong> Atk +10 melee (1d6+2); jaws spring shut around the creature's ankle and hold the creature immobile; the creature can escape with a DC 20 Disable Device check, DC 24 Escape Artist check, or DC 28 Strength check.</p>
<p><strong>Sawtooth Bear Trap - CR 5</strong><br/><strong>Type</strong> mechanical; <strong>Perception</strong> DC 25; <strong>Disable Device</strong> DC 25<br/><strong>Effects</strong><br/><strong>Trigger</strong> location; <strong>Reset</strong> manual<br/><strong>Effect</strong> Atk +15 melee (3d6+9); serrated jaws spring shut around the creature's ankle and halve the creature's base speed (or hold the creature immobile if the trap is attached to a solid object); the creature can escape with a DC 25 Disable Device check, DC 28 Escape Artist check, or DC 32 Strength check.</p>
</blockquote>
</>};
const _bear_trap = {title: "Bear trap", jsx: <><h2 id="eq-misc-bear_trap-bear-trap">Bear trap</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 77</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 184</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 10 lbs.<br/><strong>Category</strong> Tools</p>
<p>Although intended for trapping large animals, bear traps work as well for trapping humanoids or monsters. The hinged jaws of the trap are attached to a chain, which in turn is secured to a spike driven into the ground to ensure that the victim cannot simply crawl away. Prying open the jaws or pulling the spike from the ground requires a DC 20 Strength check.</p>
<p><strong>Bear Trap - CR 1</strong><br/><strong>Type</strong> mechanical; <strong>Perception</strong> DC 15; <strong>Disable Device</strong> DC 20<br/><strong>Effects</strong><br/><strong>Trigger</strong> location; <strong>Reset</strong> manual<br/><strong>Effect</strong> Atk +10 melee (2d6+3); sharp jaws spring shut around the creature's ankle and halve the creature's base speed (or hold the creature immobile if the trap is attached to a solid object); the creature can escape with a DC 20 Disable Device check, DC 22 Escape Artist check, or DC 26 Strength check.</p>
</>};
const _beast_lure = {title: "Beast lure", jsx: <><h2 id="eq-misc-beast_lure-beast-lure">Beast lure</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 30 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This light brown oil works similar to <Link to="/eq-misc/kaava_musk">Kaava musk</Link> but attracts one specific kind of creature (dogs, giant bees, and so on).</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _beast_whistle = {title: "Beast whistle", jsx: <><h2 id="eq-misc-beast_whistle-beast-whistle">Beast whistle</h2>
<p><strong>Sources</strong> <Link to="/source/familiar_folio">Familiar Folio pg. 20</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Animal Gear</p>
<p>This small wooden whistle emits a high-pitched sound like that of a <Link to="/eq-misc/signal_whistle">signal whistle</Link>, except the signal is audible only to a specific type of creature - other types of creatures hear only a quiet hissing sound.</p>
<p>Beast whistles come in six different varieties: avian, canine, feline, rodent, reptile, and ungulate (other varieties may be available at the GM's discretion). Animals and magical beasts that match a beast whistle's type can hear the whistle as a human hears a signal whistle. Creatures that fit into multiple categories (such as griffons) can usually hear the call of multiple types of whistles, though magical beasts who don't fit into any of the above categories cannot hear a beast whistle. Beast whistles don't function underwater, except if surrounded by an air bubble or similar effect, though creatures underwater may hear a beast whistle sounded from above the surface if they are close enough.</p>
</>};
const _beast_hunter_whistle = {title: "Beast-hunter whistle", jsx: <><h2 id="eq-misc-beast_hunter_whistle-beast-hunter-whistle">Beast-hunter whistle</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 26</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>This whistle produces sound at a pitch that can only be heard by aberrations, animals, dragons, fey, and magical beasts. The sound can be detected easily (Perception DC 0) from a quarter-mile away. If the user makes a successful DC 15 Perform (wind) check, all creatures within 30 feet that can hear the whistle must succeed at a DC 10 Fortitude save or be <Link to="/misc/dazzled">dazzled</Link> for 1 round (the -1 penalty applies to hearing-based, rather than sight-based, Perception checks).</p>
</>};
const _beast_scent = {title: "Beast-scent", jsx: <><h2 id="eq-misc-beast_scent-beast-scent">Beast-scent</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 24</Link>, <Link to="/source/seekers_of_secrets">Seekers of Secrets pg. 42</Link><br/><strong>Price</strong> 75 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This mixture of scent-gland extracts and aromatic herbs serves as both attractor and olfactory camouflage. It masks the natural scent of a creature with a pungent musk that is alluring to animals. Beast-scent provides a +2 circumstance bonus on Handle Animal and wild empathy checks and a -5 penalty on attempts to track the wearer by his original scent. If the tracking creature is following the smell of beast-scent itself, Survival checks to track gain a +10 circumstance bonus instead.</p>
<p>A single vial of beast-scent masks the scent of one Medium creature or two smaller creatures; larger creatures require proportionally more to gain the benefits. Beast-scent becomes inert after 1 hour of exposure to air. Applying a vial is a full-round action that provokes attacks of opportunity.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 25</p>
</>};
const _beast_training_kit = {title: "Beast-training kit", jsx: <><h2 id="eq-misc-beast_training_kit-beast-training-kit">Beast-training kit</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 12</Link><br/><strong>Price</strong> 15 gp; <strong>Weight</strong> 26 lbs.<br/><strong>Category</strong> Animal Gear</p>
<p>This kit includes a <Link to="/eq-misc/dandy_brush">dandy brush</Link>, <Link to="/eq-misc/training_harness">training harness</Link>, <Link to="/eq-misc/training_whip">training whip</Link>, <Link to="/eq-misc/whet_bone">whet bone</Link>, and 2 days' worth of <Link to="/eq-misc/carnivore_feed">carnivore feed</Link>. The weight of this kit can be reduced by 10 pounds by forgoing the carnivore feed.</p>
</>};
const _bedroll = {title: "Bedroll", jsx: <><h2 id="eq-misc-bedroll-bedroll">Bedroll</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 1 sp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This consists of two woolen sheets sewn together along the bottom and one side to create a bag for sleeping in. Some have cloth straps along the open side so the bedroll can be tied closed while you are sleeping. It can be rolled and tied into a tight coil for storage or transport. Most people use a <Link to="/eq-misc/blanket">blanket</Link> with the bedroll to stay warm or provide a ground cushion.</p>
</>};
const _bell_net = {title: "Bell net", jsx: <><h2 id="eq-misc-bell_net-bell-net">Bell net</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>Copper bells hang at each the corners of this 5-foot-by-5-foot wire net. A bell net is designed to blanket gear while you sleep, hunt, cook, or otherwise can't give it your full attention, rasing an alarm if your possessions are disturbed. Creatures attempting to access gear protected by a bell net must succeed at a DC 25 Sleight of Hand check to avoid chiming the bells. Hearing the chiming bells of a bell net requires a DC 0 Perception check. Because the many bells chime when you move, traveling with a bell net gives you a -2 penalty on Stealth checks.</p>
</>};
const _bell_tripwire_trap = {title: "Bell tripwire trap", jsx: <><h2 id="eq-misc-bell_tripwire_trap-bell-tripwire-trap">Bell tripwire trap</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 20</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This fine, 10-foot-long tripwire is attached to a loud bell and comes with pitons to fix the trap in place. The trap can be set across doorways, hallways, or narrow passes or between trees or rocks. Arming the trap properly takes 5 minutes; it can be set up in as little as 1 minute, but doing so reduces the DC to notice and disarm the trap by 5. The trap has the following statistics.</p>
<p><strong>Bell Tripwire Trap</strong><br/><strong>Type</strong> mechanical; <strong>Perception</strong> DC 20; <strong>Disable Device</strong> DC 20<br/><strong>Effects</strong><br/><strong>Trigger</strong> touch; <strong>Reset</strong> manual<br/><strong>Effect</strong> bell rings (Perception DC 0 to hear); Craft (traps) DC 15</p>
</>};
const _bell = {title: "Bell", jsx: <><h2 id="eq-misc-bell-bell">Bell</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>This handbell can produce only one loud note.</p>
</>};
const _belladonna = {title: "Belladonna", jsx: <><h2 id="eq-misc-belladonna-belladonna">Belladonna</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Black Market</p>
<p>Also known as deadly nightshade, this plant, with its distinctive greenish-purple leaves and dull black berries, has served as a cosmetic and medicine for longer than memory despite its <Link to="/eq-poison/belladonna">toxicity</Link>. It can also induce vivid but usually unpleasant hallucinations, particularly ones dealing with flight. Herbalists and others trained to use it safely believe it has numerous applications, including pain relief.</p>
</>};
const _belled_catsuit = {title: "Belled Catsuit", jsx: <><h2 id="eq-misc-belled_catsuit-belled-catsuit">Belled Catsuit</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 30</Link><br/><strong>Price</strong> 30 gp; <strong>Weight</strong> 12 lbs.<br/><strong>Category</strong> Tools</p>
<p>This form-fitting garment is strung all around with dozens of small bells. You can practice your sneaking technique by donning a belled catsuit and then attempting to move without letting any of the bells ring. Old thieves sometimes call a belled catsuit a Billy-Jacket. Training with a belled catsuit requires 1 hour of practice and a DC 25 Stealth check. If you succeed at the check, you gain a +2 circumstance bonus on Stealth checks to hide. This bonus lasts for 24 hours or until you fail a Stealth check.</p>
</>};
const _bellows = {title: "Bellows", jsx: <><h2 id="eq-misc-bellows-bellows">Bellows</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 77</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 184</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 3 lbs.<br/><strong>Category</strong> Tools</p>
<p>Bellows are useful for starting fires, providing a +1 circumstance bonus on Survival checks to start or maintain fires.</p>
</>};
const _belt_pouch = {title: "Belt pouch", jsx: <><h2 id="eq-misc-belt_pouch-belt-pouch">Belt pouch</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>A typical leather or cloth belt pouch has a leather cord to cinch it shut and another to tie it to your belt. It is large enough to hold 100-200 coins or two apples.</p>
</>};
const _billiards_gear = {title: "Billiards gear", jsx: <><h2 id="eq-misc-billiards_gear-billiards-gear">Billiards gear</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 92</Link><br/><strong>Price</strong> 5 sp; <strong>Weight</strong> 8 lbs.<br/><strong>Category</strong> Entertainment</p>
<p>This set includes a wooden cue, a block of cue chalk, 15 wooden balls, and a triangular wooden ball rack.</p>
</>};
const _billow_cape = {title: "Billow cape", jsx: <><h2 id="eq-misc-billow_cape-billow-cape">Billow cape</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 65</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> 4 lbs.<br/><strong>Category</strong> Clothing</p>
<p>This silk cape is constructed of many carefully arranged overlapping layers that are loosely stitched together. When exposed to a sudden influx of air, like that caused by falling, the cloak unfolds like a crude parachute. When falling, a creature wearing a billow cape is treated as if he had deliberately jumped from the height. When worn in areas of strong wind or greater, a billow cape hampers movement. In such wind conditions, the wearer treats all terrain as <Link to="/rule/difficult_terrain">difficult terrain</Link> and takes a -4 penalty on Fly checks. Because of the strange and somewhat fragile construction of this cape, only Small or smaller billow capes function properly. Larger billow capes take all the penalties resulting from high winds, but grant none of the benefits when the wearer falls.</p>
</>};
const _billy_ten_bells = {title: "Billy Ten-Bells", jsx: <><h2 id="eq-misc-billy_ten_bells-billy-ten-bells">Billy Ten-Bells</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 30</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 6 lbs.<br/><strong>Category</strong> Tools</p>
<p>Bearing a marked resemblance to an anthropomorphic wind chime, this complicated arrangement of strings, sticks, and bells is hung from a ceiling or branch and has a purse or money-pouch deep inside. The trick is to silently steal a coin from Billy Ten-Bells, as the slightest movement will set the bells ringing. Veteran thieves sometimes decorate Billy with scraps of stolen clothing for good luck. Training with Billy Ten-Bells requires 1 hour of practice and a DC 20 Sleight of Hand check. If you succeed at the check, you gain a +2 circumstance bonus on Sleight of Hand checks to pick pockets. This bonus lasts for 24 hours or until you fail a Sleight of Hand check.</p>
</>};
const _bird_feed_per_day = {title: "Bird feed (per day)", jsx: <><h2 id="eq-misc-bird_feed_per_day-bird-feed-per-day">Bird feed (per day)</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 12</Link><br/><strong>Price</strong> 5 cp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Animal Gear</p>
<p>This mixture of seed and dead insects is suitable food for small birds such as ravens, crows, and chickens. Birds of prey such as falcons, hawks, and owls can also sustain themselves on bird feed, though they typically require at least two servings per day. Larger avian creatures such as axe beaks and griffons require larger portions of meat, and cannot survive on bird feed alone.</p>
</>};
const _bird_training_kit = {title: "Bird-training kit", jsx: <><h2 id="eq-misc-bird_training_kit-bird-training-kit">Bird-training kit</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 12</Link><br/><strong>Price</strong> 17 gp; <strong>Weight</strong> 8 lbs.<br/><strong>Category</strong> Animal Gear</p>
<p>This kit includes a <Link to="/eq-misc/falconry_gauntlet">falconry gauntlet</Link>, <Link to="/eq-misc/tiny_cage">Tiny cage</Link>, <Link to="/eq-misc/training_whip">training whip</Link>, and 2 days' worth of <Link to="/eq-misc/bird_feed">bird feed</Link>.</p>
</>};
const _bit_and_bridle = {title: "Bit and bridle", jsx: <><h2 id="eq-misc-bit_and_bridle-bit-and-bridle">Bit and bridle</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 81</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 159</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Animal Gear</p>
<p>This is headgear used by a rider to control a mount. Bit and bridles for horses, ponies, and riding dogs can be readily purchased in most settlements and bits and bridles can be crafted for any creature that serves as a mount.</p>
</>};
const _black_amaranth = {title: "Black Amaranth", jsx: <><h2 id="eq-misc-black_amaranth-black-amaranth">Black Amaranth</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 152</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> -<br/><strong>Category</strong> <Link to="/rule/herbalism">Herbs</Link><br/><strong>Gather</strong> DC 18; <strong>Yield</strong> 1 dose<br/><strong>Terrain</strong> temperate or warm forests or plains<br/><strong>Preparation</strong> The amaranth's flowers and stalks must be carefully ground into paste. This requires a successful DC 12 Craft (alchemy) check and 1 hour of work.<br/><strong>Use</strong> A dose of black amaranth paste can be applied to a dead body to slow decay. One dose used on a Tiny or smaller creature delays the onset of decay for 3 days (as per <Link to="/spell/gentle_repose">gentle repose</Link>). Two doses are needed for Small creatures, 3 for Medium creatures, 6 for Large creatures, 12 for Huge creatures, 24 for Gargantuan creatures, and 48 for Colossal creatures. Each dose applied requires a full-round action that provokes attacks of opportunity.</p>
<p>Black amaranth grows in small clusters from the remains of the dead.</p>
</>};
const _black_cumin = {title: "Black cumin", jsx: <><h2 id="eq-misc-black_cumin-spices">Spices</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 14</Link><br/><strong>Price</strong> 15 gp (Black cumin), 20 gp (Flaming sumac), 30 gp (Golden cardamom), 100 gp (Striped nutmeg), 15 gp (Sunrise cinnamon), 25 gp (Tiger cloves), 5 gp (Violet salt); <strong>Weight</strong> -</p>
<p>Food spoils more quickly in hot climates, and Qadirans have become experts at using the spices that they trade to help preserve their meals. After importing plants from across the planes, Qadiran druids and alchemists bred and magically adapted unique species with enhanced medicinal properties. <Link to="/rule/al_zabriti">Al-Zabriti</Link> tribes generally have supplies of the following spices on hand. To gain the benefits of these spices, a character must consume multiple doses over 1 or more days, as indicated for each spice. Once the benefit is gained, continued consumption at that rate maintains the benefit.</p>
<p><strong>Black Cumin:</strong> Cumin is a nutty seasoning used in savory foods. If eaten twice per day for a week, it grants those who consume it a +1 alchemical bonus on Fortitude saves to resist disease for the following 24 hours. An ounce of black cumin sells for 15 gp and seasons 14 meals.</p>
<p><strong>Flaming Sumac:</strong> A tart spice, sumac allows a character who contracts a natural disease with multiple effects to suffer one fewer effect (determined randomly) each time he fails a saving throw to resist that disease's effects. An individual must consume flaming sumac twice per day for at least 3 days to gain its effects, which last for 24 hours after the last dose is consumed. An ounce of flaming sumac sells for 20 gp and seasons six meals.</p>
<p><strong>Golden Cardamom:</strong> This fragrant, sweet powder is made from ground cardamom seeds and is often used as a perfume and tooth cleaner, as well as a seasoning in rice dishes and desserts. When a character takes ability damage from a disease, the actual damage taken is reduced by 1 (to a minimum of 0). Golden cardamom has no effect on ability drain or other effects caused by disease. It must be eaten once per day for 9 days to build up sufficiently within an individual's body to provide this effect. An ounce of golden cardamom seeds sells for 30 gp and seasons nine meals.</p>
<p><strong>Striped Nutmeg:</strong> Used for both desserts and meats, nutmeg halves any ability damage (but not ability drain) resulting from non-supernatural disease, to a minimum damage of 1. It must be eaten three times per day for at least 4 days to provide this effect. An ounce of ground striped nutmeg sells for 100 gp and seasons 12 meals.</p>
<p><strong>Sunrise Cinnamon:</strong> A warming spice, sunrise cinnamon is used for seasoning both sweet and savory foods. It promotes sweating, and a character who ingests it twice per day for 5 days gains a +4 alchemical bonus on Fortitude saves made to resist the effects of <Link to="/rule/heat_dangers">hot environments</Link>. An ounce of ground sunrise cinnamon sells for 15 gp and seasons 10 meals.</p>
<p><strong>Tiger Cloves:</strong> Cloves are used in both sweet and savory foods, brewed into teas, and chewed as a breath freshener. When chewed for 1 minute, a dose of tiger cloves removes nauseated or sickened conditions caused by disease or poison effects. When used to season a meal, a dose of tiger cloves grants a +2 alchemical bonus on saving throws to resist the nauseated or sickened conditions for 24 hours after the meal is eaten. A single dose of tiger cloves sells for 25 gp and seasons one meal.</p>
<p><strong>Violet Salt:</strong> Salt is of vital importance for retaining a body's water. If a dose of Qadiran violet salt is consumed as part of a meal, it grants a +4 alchemical bonus on Constitution checks to resist the effects of ongoing <Link to="/rule/thirst">thirst</Link> for the next 24 hours. A dose of violet salt sells for 5 gp and seasons one meal.</p>
</>};
const _black_fester_vial = {title: "Black fester (vial)", jsx: <><h2 id="eq-misc-black_fester_vial-black-fester-vial">Black fester (vial)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 56</Link><br/><strong>Price</strong> 30 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Tools</p>
<p>This black paste is often applied on orc weapons before going on raids to stymie an enemy's healing magic. Like a poison, black fester stays on a weapon until the first time it strikes an opponent. It remains in the target's body for 1 hour. A creature exposed to black fester resists magical healing; a creature trying to magically heal the target must make a DC 10 caster level check to restore any hit points to the target.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 25</p>
</>};
const _blackfingers_paste = {title: "Blackfingers paste", jsx: <><h2 id="eq-misc-blackfingers_paste-blackfingers-paste">Blackfingers paste</h2>
<p><strong>Sources</strong> <Link to="/source/rival_guide">Rival Guide pg. 53</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Tools</p>
<p>Developed by followers of Norgorber, this inky paste aids unskilled poison-users. When smeared on the fingers, a dose of blackfingers paste prevents accidental poisoning while applying poison to a weapon, as if the user possessed the <Link to="/ability/poison_use">poison use</Link> ability. A single dose of blackfingers paste lasts for 1d6 hours, but the black stains the stuff creates on the user's fingers lasts for days. A single dose of this alchemical item costs 50 gp.</p>
</>};
const _blackfire_clay = {title: "Blackfire clay", jsx: <><h2 id="eq-misc-blackfire_clay-blackfire-clay">Blackfire clay</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 103</Link><br/><strong>Price</strong> 20 gp; <strong>Weight</strong> 10 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This pliant black clay is always pleasantly warm to the touch. Working blackfire clay in your hands for a full round causes the clay to grow much warmer, granting you a +4 alchemical bonus on saving throws made to resist <Link to="/rule/cold">cold weather</Link>. You can combine five blocks of clay over the course of a minute to produce a source of warmth equivalent to a small campfire, allowing you to heat a campsite and cook food.</p>
<p>Blackfire clay only produces heat, never light, smoke, or odor. The clay emits warmth for 1 hour before hardening into an unusable lump. A newly created brick of blackfire clay is composed of 10 blocks.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _blackwood_figurehead = {title: "Blackwood figurehead", jsx: <><h2 id="eq-misc-blackwood_figurehead-blackwood-figurehead">Blackwood figurehead</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 9</Link><br/><strong>Price</strong> 650 gp; <strong>Weight</strong> 25 lbs.<br/><strong>Category</strong> Tools</p>
<p>Carved in the likeness of a sea creature or another form desired by the one commissioning it, this item grants its ship's crew a +2 morale bonus on Profession (sailor) checks while on board.</p>
</>};
const _bladeguard = {title: "Bladeguard", jsx: <><h2 id="eq-misc-bladeguard-bladeguard">Bladeguard</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 101</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 184</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 40 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Remedies</p>
<p>This clear resin protects a weapon from harmful attacks made by oozes and <Link to="/monster/rust_monster">rust monsters</Link>, as well as from similar effects that corrode or melt weapons, rendering the weapon immune for 24 hours. One pot can coat one two-handed weapon, two one-handed or light weapons, or 50 ammunition items. Applying it takes 1 full round per pot. Immersing the weapon in water or similar liquid washes it off.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 15</p>
</>};
const _blain_bane = {title: "Blain bane", jsx: <><h2 id="eq-misc-blain_bane-blain-bane">Blain bane</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 9</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Remedies</p>
<p>This alchemically infused wax is spread over exposed skin to protect it from chapping, cold, dry winds, heat, and the loss of moisture. Applying it takes 5 minutes; once applied, it reduces any nonlethal damage taken from <Link to="/rule/cold">cold</Link> or <Link to="/rule/heat_dangers">hot</Link> environments by 1 point for 6 hours. Crafting blain bane requires a successful DC 19 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 19</p>
</>};
const _blanket = {title: "Blanket", jsx: <><h2 id="eq-misc-blanket-blanket">Blanket</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 181</Link><br/><strong>Price</strong> 5 sp; <strong>Weight</strong> 3 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This warm, woven blanket has straps so it can be rolled up and tied. Blankets are often used in conjunction with <Link to="/eq-misc/bedroll">bedrolls</Link> to provide additional warmth or a ground cushion.</p>
</>};
const _blasting_jelly = {title: "Blasting jelly", jsx: <><h2 id="eq-misc-blasting_jelly-blasting-jelly">Blasting jelly</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 30</Link><br/><strong>Price</strong> 45 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This volatile gray paste sticks to solid surfaces and creates a concentrated blast when exposed to fire, making it a valuable excavation tool. You can apply 1 dose of blasting jelly to a 5-foot square as a standard action. The paste can be ignited with another standard action by striking it from an adjacent square with a metal weapon or object. When thus ignited or otherwise exposed to fire, the jelly explodes, dealing 2d6 points of fire damage to creatures and unattended objects within the treated square. If the ignited square is adjacent to another square containing blasting jelly, that square ignites as well. Blasting jelly deals full damage to objects made of stone or softer material. Blasting jelly decays relatively quickly when exposed to air, becoming inert after 4 hours if not ignited.</p>
</>};
const _blight_tonic = {title: "Blight tonic", jsx: <><h2 id="eq-misc-blight_tonic-blight-tonic">Blight tonic</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 153</Link><br/><strong>Price</strong> 150 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>Blight tonic increases the potency of a creature's disease attack transmitted by physical contact, such as a <Link to="/monster/dire_rat">dire rat's</Link> <Link to="/disease/filth_fever">filth fever</Link>. The next time a creature must save against the drinker's disease save DC, the DC for the initial infection increases by +2. The tonic lasts for 10 minutes or until the next time a creature must save against the drinker's disease DC, whichever comes first.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _blightburn_paste = {title: "Blightburn paste", jsx: <><h2 id="eq-misc-blightburn_paste-blightburn-paste">Blightburn paste</h2>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion pg. 29</Link><br/><strong>Price</strong> 5,000 gp; <strong>Weight</strong> 45 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This heavy stone box measures 2 feet to a side, and the tiny compartment inside is lined with lead. Inside the compartment is a half-ounce of deep green paste. This paste is made of animal fat mixed with groundup <Link to="/eq-material/blightburn">blightburn</Link>. Once the box is opened, blightburn paste limits teleportation within 60 feet and irradiates anyone within 60 feet, afflicting them with <Link to="/disease/blightburn_sickness">blightburn sickness</Link>. Any creature that touches the paste is afflicted with blightburn sickness (no save), and takes 2d6 points of fire damage per round until the paste is cleaned away with a successful DC 15 Heal check. Crafting this item requires a successful DC 30 Craft (alchemy) check.</p>
<h3 id="eq-misc-blightburn_paste-blightburn">Blightburn</h3>
<p>The mineral blightburn is the deadliest radioactive substance in the Darklands. The green-glowing crystal burns anyone who touches it, dealing 2d6 points of fire damage per round of contact, and its radiation causes blightburn sickness. The substance also limits teleportation. Anyone casting a teleportation spell in or teleporting to a cavern with blightburn in its walls must succeed at a DC 30 caster level check.</p>
</>};
const _blightburn_reader = {title: "Blightburn reader", jsx: <><h2 id="eq-misc-blightburn_reader-blightburn-reader">Blightburn reader</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 10</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>A blightburn reader is a small wooden or metal frame, roughly 2 inches wide and 4 inches long, containing a specially prepared alchemical paper pressed between two thin panes of glass. Whenever a character wearing a blightburn reader enters an area with a radiation hazard, the paper within changes from white to black over the course of 1 minute. Once the paper turns black, it is destroyed and must be replaced at a cost of 15 gp before the blightburn reader can be used again.</p>
</>};
const _block_and_tackle = {title: "Block and tackle", jsx: <><h2 id="eq-misc-block_and_tackle-block-and-tackle">Block and tackle</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 185</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>Whether it is used to hoist treasure from a pit or move supplies, a simple block-and-tackle pulley, when it is properly secured, adds a +5 circumstance bonus on Strength checks to lift heavy objects. Securing the pulley requires 1 minute.</p>
</>};
const _blood_neutralizer = {title: "Blood neutralizer", jsx: <><h2 id="eq-misc-blood_neutralizer-blood-neutralizer">Blood neutralizer</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_sea">Blood of the Sea pg. 18</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>When you release this vial of alchemical particles into the water as a standard action, the particles immediately neutralize the scent of exposed blood within 20 feet, rendering the blood undetectable by <Link to="/umr/scent">scent</Link> (to a hunting shark, for example). Blood neutralizer has no effect on any blood that enters the area after the particles have been used. Blood neutralizer can be crafted with a successful DC 25 Craft (alchemy) skill check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 25</p>
</>};
const _blood_boiling_pill = {title: "Blood-boiling pill", jsx: <><h2 id="eq-misc-blood_boiling_pill-blood-boiling-pill">Blood-boiling pill</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 24</Link><br/><strong>Price</strong> 75 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Remedies</p>
<p>Swallowing this dark black-red tea pill causes your blood to heat up, granting you a +2 alchemical bonus on initiative checks and on saving throws against cold effects for 8 hours. However, any damage you take from <Link to="/rule/bleed">bleed</Link> effects during this time is multiplied by 1-1/2 (rounded up). Swallowing a <Link to="/eq-misc/blood_chilling_pill">blood-chilling pill</Link> while under the effects of a blood-boiling pill negates the effects of both pills.</p>
<p><strong><Link to="/rule/spontaneous_alchemy">Spontaneous Alchemy</Link> Recipe</strong> (30 ginger extract + 8 gold + 15 mugwort extract)/ceration; <strong>Craft DC</strong> 25<br/><strong>Time</strong> 10 minutes; <strong>Tools</strong> <Link to="/eq-misc/crucible">crucible</Link>; <strong>Type</strong> alchemical remedy</p>
</>};
const _blood_chilling_pill = {title: "Blood-chilling pill", jsx: <><h2 id="eq-misc-blood_chilling_pill-blood-chilling-pill">Blood-chilling pill</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 25</Link><br/><strong>Price</strong> 75 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Remedies</p>
<p>Swallowing this pale green tea pill causes your blood to slow and chill, allowing you to ignore the first 20 points of <Link to="/rule/bleed">bleed</Link> damage you take during the following 8 hours. In addition, you gain a +2 alchemical bonus on saving throws against fire effects during this time. However, you take a -2 penalty on initiative checks. Swallowing a <Link to="/eq-misc/blood_boiling_pill">blood-boiling pill</Link> while under the effects of a blood-chilling pill negates the effects of both pills.</p>
<p><strong><Link to="/rule/spontaneous_alchemy">Spontaneous Alchemy</Link> Recipe</strong> (15 ginger extract + 40 myrrh + 30 mugwort extract)/filtration; <strong>Craft DC</strong> 25<br/><strong>Time</strong> 10 minutes; <strong>Tools</strong> <Link to="/eq-misc/filter">filter</Link>; <strong>Type</strong> alchemical remedy</p>
</>};
const _blood_clotter_salve = {title: "Blood-clotter salve", jsx: <><h2 id="eq-misc-blood_clotter_salve-blood-clotter-salve">Blood-clotter salve</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 206</Link><br/><strong>Price</strong> 30 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Remedies</p>
<p>Applying this herbal salve to a <Link to="/rule/bleed">bleeding</Link> wound cures 1 point of damage and prevents additional damage from bleeding for 1 hour per application. After an hour, if the bleed effect hasn't been properly treated, the injury resumes bleeding and more salve must be applied. Though blood-clotter salve can be applied successively to the same injury, applying multiple doses doesn't cure additional damage.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _bloodblock = {title: "Bloodblock", jsx: <><h2 id="eq-misc-bloodblock-bloodblock">Bloodblock</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 103</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 184</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Tools</p>
<p>This gooey, pinkish substance helps treat wounds. Using a dose gives you a +5 alchemical bonus on Heal checks for providing first aid, treating wounds made by <Link to="/eq-misc/caltrops">caltrops</Link> or similar objects, or treating deadly wounds. A dose of bloodblock ends a <Link to="/rule/bleed">bleed</Link> effect as if you had made a DC 15 Heal check. When treating deadly wounds, using a dose of bloodblock counts as one use of a <Link to="/eq-misc/healers_kit">healer's kit</Link> (and grants the +5 bonus stated above).</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 25</p>
</>};
const _bloodgorge = {title: "Bloodgorge", jsx: <><h2 id="eq-misc-bloodgorge-bloodgorge">Bloodgorge</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 6</Link><br/><strong>Price</strong> 40 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Alchemical Remedies</p>
<p>When you imbibe this syrupy black serum, your blood thins dramatically and gushes forth from even minor wounds. Anytime you take <Link to="/rule/bleed">bleed</Link> damage, any creatures adjacent to you must succeed at a Fortitude save (DC 10 + the amount of bleed damage taken) or be <Link to="/misc/nauseated">nauseated</Link> for 1 round. A dose of bloodgorge lasts for 1 hour.</p>
<p><strong><Link to="/rule/spontaneous_alchemy">Spontaneous Alchemy</Link> Recipe</strong> (5 cold iron + 10 dew of lunary)/filtration; <strong>Craft DC</strong> 25<br/><strong>Time</strong> 10 minutes; <strong>Tools</strong> <Link to="/eq-misc/filter">filter</Link>; <strong>Type</strong> alchemical remedy</p>
</>};
const _bloodragers_kit = {title: "Bloodrager's kit", jsx: <><h2 id="eq-misc-bloodragers_kit-bloodragers-kit">Bloodrager's kit</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 202</Link><br/><strong>Price</strong> 9 gp; <strong>Weight</strong> 27 lbs.<br/><strong>Category</strong> Kits</p>
<p>This kit includes a <Link to="/eq-misc/backpack">backpack</Link>, a <Link to="/eq-misc/blanket">blanket</Link>, a <Link to="/eq-misc/belt_pouch">belt pouch</Link>, a <Link to="/eq-misc/flint_and_steel">flint and steel</Link>, an <Link to="/eq-misc/iron_pot">iron pot</Link>, <Link to="/eq-misc/soap">soap</Link>, <Link to="/eq-misc/torches">torches</Link> (10), <Link to="/eq-misc/trail_rations">trail rations</Link> (5 days), and a <Link to="/eq-misc/waterskin">waterskin</Link>.</p>
</>};
const _bloodvine_rope = {title: "Bloodvine rope", jsx: <><h2 id="eq-misc-bloodvine_rope-bloodvine-rope">Bloodvine rope</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 207</Link><br/><strong>Price</strong> 200 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This 50-foot length of tough, lightweight rope is made from alchemically treated bloodvine, a rare scarlet-colored vine that grows only in warm jungle environments. Though prized by climbers for its durability, bloodvine can also be used to bind creatures. Bloodvine rope has a hardness of 5 and 10 hit points, and can be broken with a DC 30 Strength check. A creature bound by bloodvine rope can escape with a DC 35 Escape Artist check or a DC 30 Strength check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 30</p>
</>};
const _bloody_mandrake = {title: "Bloody Mandrake", jsx: <><h2 id="eq-misc-bloody_mandrake-bloody-mandrake">Bloody Mandrake</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 153</Link><br/><strong>Price</strong> 15 gp; <strong>Weight</strong> -<br/><strong>Category</strong> <Link to="/rule/herbalism">Herbs</Link><br/><strong>Gather</strong> DC 20; <strong>Yield</strong> 1d4 doses<br/><strong>Terrain</strong> any plains or swamps<br/><strong>Preparation</strong> A bloody mandrake must be pulped so that its sticky red sap can be gathered, skimmed, and then refined into an even stickier paste; this process requires a successful DC 15 Craft (alchemy) check and 1d4 hours of work per yield.<br/><strong>Use</strong> One dose of bloody mandrake paste smeared on the lips (this is a free action) during spellcasting can be used as an additional material component when casting spells that remove afflictions and conditions or that provide a morale bonus. Doing so grants a +1 bonus to the spell's effective caster level.</p>
<p>Bloody mandrakes grow from the corpses of intelligent creatures who had supernatural powers in life. This plant's unsettlingly humanoid-shaped tuber-like roots increase fertility and vitality.</p>
</>};
const _blue_book = {title: "Blue book", jsx: <><h2 id="eq-misc-blue_book-blue-book">Blue book</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This book details the seedier entertainment establishments in one major city. It contains the names of brothels, burlesque houses, and gambling halls in that city. By consulting the book for 1 hour, for the next 24 hours you gain a +2 circumstance bonus on Knowledge (local), Bluff, and Diplomacy checks to gather or use information in that city. At the GM's discretion, you can use it in settlements near that city for a +1 bonus.</p>
</>};
const _boars_bellow = {title: "Boar's bellow", jsx: <><h2 id="eq-misc-boars_bellow-boars-bellow">Boar's bellow</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 236</Link><br/><strong>Price</strong> 190 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Tools</p>
<p>When imbibed, this bitter, rust-colored concoction grants you 1d4 uses of <Link to="/misc/alchemical_inspiration">alchemical inspiration</Link> that can be used only on Intimidate checks. The benefits of boar's bellow last for 1 hour; during this time, you must roll all Diplomacy checks twice and take the worse result.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 15</p>
</>};
const _board_game = {title: "Board game", jsx: <><h2 id="eq-misc-board_game-board-game">Board game</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 92</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 1 sp-10 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Entertainment</p>
<p>Board games have innumerable types and variations. Siege, a strategy game where players try to surround the other's pieces, is popular with older adults, while more chaotic games like Wyvern's Race and Doppel are tavern favorites.</p>
</>};
const _bodybalm = {title: "Bodybalm", jsx: <><h2 id="eq-misc-bodybalm-bodybalm">Bodybalm</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Tools</p>
<p>When this pungent yellow powder is boiled in water and given to a creature to drink, it provides the attending healer a +5 alchemical bonus on <Link to="/skill/heal">Heal</Link> checks for providing long-term care, treating poison, and treating disease.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 25</p>
</>};
const _bogwalking_sandals = {title: "Bogwalking sandals", jsx: <><h2 id="eq-misc-bogwalking_sandals-bogwalking-sandals">Bogwalking sandals</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 9</Link><br/><strong>Price</strong> 250 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Clothing</p>
<p>These sandals have blackwood soles and leather straps that wrap around the wearer's feet. The sandals are waterproof and are thus popular among individuals who tread the harsh locales of the swamps and wastelands beyond Cassomir proper - especially those who are in such environments for long periods of time without access to the comforts of a skilled cobbler. The sandals' design also allows the wearer to <Link to="/rule/marsh_terrain">move through shallow bogs</Link> normally and to treat deep bogs as if they were shallow bogs. The sandals do not affect the penalty on <Link to="/skill/acrobatics">Acrobatics</Link> checks while in bogs, and creatures wearing the sandals cannot gain <Link to="/rule/cover">cover</Link> from deep bogs.</p>
</>};
const _boline = {title: "Boline", jsx: <><h2 id="eq-misc-boline-boline">Boline</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 16</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Tools</p>
<p>Bolines are hook-shaped knives commonly used by herbalists and spellcasters to harvest ingredients for their craft. A boline's blade is typically 5 inches long, and is too small and irregular to use as a weapon. You can use a boline to finely slice the herbs in a <Link to="/eq-misc/healers_kit">healer's kit</Link>, so you can treat deadly wounds with only a single use from a healer's kit rather than two uses.</p>
</>};
const _bomb_launcher = {title: "Bomb launcher", jsx: <><h2 id="eq-misc-bomb_launcher-bomb-launcher">Bomb launcher</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 117</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>These odd looking, egg-shaped contraptions have cleverly placed fins that improve bombs' accuracy. Goblin alchemists use these special containers to make their bombs more accurate when thrown long distances. Using a bomb launcher when throwing a bomb increases the bomb's range increment to 30 feet (or increases the range increment of a bomb with the <Link to="/discovery/rocket_bomb">rocket bomb</Link> discovery to 70 feet). Bomb launchers are destroyed when used.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 25</p>
</>};
const _bombchucker = {title: "Bombchucker", jsx: <><h2 id="eq-misc-bombchucker-bombchucker">Bombchucker</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 117</Link><br/><strong>Price</strong> 12 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Tools</p>
<p>This curved wicker basket is worn like a glove over one hand. The basket extends approximately 2 feet in a steady curve, allowing you to launch a thrown splash weapon at incredible speeds and over long distances. Using a bombchucker increases the range increment of any thrown splash weapon by 10 feet. Loading a bombchucker requires a free hand, as the hand wielding the bombchucker can't be used for any other purpose. A bombchucker doesn't get in the way of preparing and throwing a bomb created with the bomb class feature.</p>
</>};
const _bone_reed = {title: "Bone Reed", jsx: <><h2 id="eq-misc-bone_reed-bone-reed">Bone Reed</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 153</Link><br/><strong>Price</strong> 75 gp; <strong>Weight</strong> -<br/><strong>Category</strong> <Link to="/rule/herbalism">Herbs</Link><br/><strong>Gather</strong> DC 24; <strong>Yield</strong> 1 dose<br/><strong>Terrain</strong> any swamps<br/><strong>Preparation</strong> A bone reed must be pressed and dried. This process requires a successful DC 10 Craft (alchemy) check and takes 8 hours to complete.<br/><strong>Use</strong> A creature that sleeps for at least 8 hours in 1 day with a bone reed bound to one of its arms or legs <Link to="/rule/heals">heals</Link> double the normal ability damage and hit point damage (or triple with full bed rest). A bone reed loses its effectiveness after use. Binding a bone reed to a limb requires 1 minute of work.</p>
<p>This aquatic grass resembles translucent white horsetail.</p>
</>};
const _bone_paste = {title: "Bone paste", jsx: <><h2 id="eq-misc-bone_paste-bone-paste">Bone paste</h2>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook pg. 26</Link><br/><strong>Price</strong> 75 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>Typically stored in an airtight leather wineskin cured with rare preservative unguents, bone paste is a powerful alchemical sealant with special deteriorative properties. When squeezed out of its container and exposed to air, bone paste quickly hardens, so in order to apply it to a surface or object one must typically squeeze the paste directly onto the material to be affected. Once applied, bone paste cements itself to the object in just seconds, and hardens into a flaky cast. If applied to any unattended organic material or surface (such as wood, paper, hide, or rope), after 1 hour, bone paste undergoes another alchemical reaction and begins to eat away at the material, dealing 1d4 points of damage each round for 1d6+1 rounds, eating away first at the part of the object to which it was applied and spreading briefly to other parts of the object before dissipating and leaving a small amount of residual dust. Bone paste ignores an organic object's hardness, and does not deal damage to inorganic objects or surfaces (such as metal, stone, or ceramic). One pouch of bone paste is enough to cover 1 square foot of surface, or (because of waste and spills) up to 20 smaller applications of approximately 2 square inches each.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _boniface_paint = {title: "Boniface paint", jsx: <><h2 id="eq-misc-boniface_paint-boniface-paint">Boniface paint</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 44</Link>, <Link to="/source/pathfinder_106_for_queen_and_empire">Pathfinder #106: For Queen and Empire pg. 75</Link><br/><strong>Price</strong> 15 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This thick whitewash is laced with exotic oils, and it dries to a lovely finish run through with subtle swirls. Difficult to notice, these patterns help obscure seams and details in whatever the paint coats; the <Link to="/skill/perception">Perception</Link> DC to find a secret door or hidden compartment on a surface covered in boniface paint increases by 5. One bucket of boniface paint covers up to a 10-foot-by-10-foot area, and its concealing effects last for 1 year. Crafting a bucket of boniface paint requires a successful DC 20 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _book_lariat = {title: "Book lariat", jsx: <><h2 id="eq-misc-book_lariat-book-lariat">Book lariat</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 202</Link><br/><strong>Price</strong> 3 sp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This braided metal cord comes with a clasp that affixes to the lock of a standard spellbook. The other end of the cord attaches to a belt or belt loop. The cord is 10 feet long and retractable. If you drop your spellbook while it's attached to the lariat, you can recover the spellbook as a standard action. While attached to you, the book can never be farther than 10 feet from you. Unclasping the book requires a move action, or the cord can be cut to free the book (hardness 5, hp 10).</p>
</>};
const _book_of_letters = {title: "Book of letters", jsx: <><h2 id="eq-misc-book_of_letters-book-of-letters">Book of letters</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 3 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This portfolio contains examples of official letters along with proper forms of address, etiquette, and turns of phrase. Used by bureaucrats, diplomats, and clerks, it's also useful for counterfeiting official correspondence. It provides a +2 circumstance bonus on Diplomacy checks when dealing with city officials and a +2 circumstance bonus on Linguistics checks when creating forgeries. A book of letters is only accurate for a particular region, such as a country or even a town, and only provides its bonus relating to that region.</p>
</>};
const _book_of_puzzles = {title: "Book of puzzles", jsx: <><h2 id="eq-misc-book_of_puzzles-book-of-puzzles">Book of puzzles</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 202</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Entertainment</p>
<p>Each book contains 10 puzzles made to test the mind and stir the intellect. Solving a single puzzle requires at least an hour and a successful DC 10 Intelligence check, though every 5 points by which you exceed the check reduces the amount of time you need to solve the puzzle by 10 minutes (to a minimum of 10 minutes to solve an individual puzzle). Once you solve a puzzle, for the next 24 hours you can choose to roll twice on a single Disable Device, Knowledge, or Sense Motive skill check and take the higher result. Once all the puzzles are solved, the book is useless, though you can purchase another puzzle book with different puzzles.</p>
</>};
const _book_of_war_prayers = {title: "Book of war prayers", jsx: <><h2 id="eq-misc-book_of_war_prayers-book-of-war-prayers">Book of war prayers</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 202</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This small, leather-bound collection of war prayers features pages of fine vellum. If you have a Charisma of 13 or higher, or at least 1 rank in Perform (oratory), you can read aloud prayers from the book before battle to hearten others for the trials to come. Reading prayers for this effect takes 10 minutes. You grant those who hear your prayers a +2 morale bonus on the next saving throw against fear they attempt, as long as that saving throw is made in the next 24 hours.</p>
</>};
const _bore_brush = {title: "Bore brush", jsx: <><h2 id="eq-misc-bore_brush-bore-brush">Bore brush</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes pg. 14</Link><br/><strong>Price</strong> 75 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This spiraled metal rod has alchemically treated bristles that can be used in the barrel of an early or advanced firearm to liquefy grime and bullet fouling while leaving a thin protective film in the bore. Using this brush is a standard action, and the protective film grants a 5-foot alchemical bonus to the firearm's first range increment and a +1 alchemical bonus on attack rolls. These effects last for 1 hour or until the firearm is fired. A newly crafted bore brush contains 5 applications. Crafting a bore brush requires a successful DC 15 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 15</p>
</>};
const _bottle = {title: "Bottle", jsx: <><h2 id="eq-misc-bottle-bottle">Bottle</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This glass bottle holds about a pint and includes a cork.</p>
</>};
const _bottled_musk = {title: "Bottled musk", jsx: <><h2 id="eq-misc-bottled_musk-bottled-musk">Bottled musk</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 26</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This glass vial contains alchemically preserved musk from a single variety of creature. Sniffing bottled musk provides a +4 circumstance bonus on Survival checks to track creatures of the same variety by <Link to="/umr/scent">scent</Link>. Additionally, bottled musk can be used as an additional spell component for the following spells to modify the spell's effects.</p>
<blockquote>
<p><strong>Detect undead:</strong> Functions as written, but detects creatures of the musk's associated creature type.</p>
<p><strong>Locate creature:</strong> Detects the same variety of creature as the musk (for example, using bison musk detects only bison, not all herd animals or animals), and provides a +2 bonus on caster level checks to overcome nondetection.</p>
</blockquote>
</>};
const _bottled_sunlight = {title: "Bottled sunlight", jsx: <><h2 id="eq-misc-bottled_sunlight-bottled-sunlight">Bottled sunlight</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 13</Link><br/><strong>Price</strong> 200 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>As a standard action, this ornate rectangular jar can be vigorously shaken to cause its contents to mix and activate. Once shaken, the contents of the jar shed light as a <Link to="/eq-misc/sunrod">sunrod</Link> for 6 hours. A jar of activated bottled sunlight can be thrown as a splash weapon with a range increment of 10 feet. Upon striking a solid object, the bottled sunlight creates a 30-foot-radius <Link to="/misc/burst">burst</Link> of natural sunlight that persists for 1 round, after which all light from the jar fades. Throwing an inactive jar of bottled sunlight destroys the item, leaving only a smoldering pile of ashes where it struck. Crafting this item requires a successful DC 30 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 30</p>
</>};
const _bottom_walkers_anchor = {title: "Bottom-walker's anchor", jsx: <><h2 id="eq-misc-bottom_walkers_anchor-bottom-walkers-anchor">Bottom-walker's anchor</h2>
<p><strong>Sources</strong> <Link to="/source/aquatic_adventures">Aquatic Adventures pg. 56</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> 50 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This dense anchor is attached to a sturdy but easily detachable chain (removing the chain is a move action). Wearing a bottomwalker's anchor all but guarantees an undersea explorer a swiftly sinking <Link to="/rule/buoyancy">buoyancy</Link>, though it also increases her armor check penalty by 1 and decreases her maximum Dexterity bonus by 1 (or sets it at +6, if the wearer didn't have a maximum Dexterity bonus). Compared to simply carrying plenty of dense items, it's unwieldy, but the advantage is that the undersea explorer can detach the anchor in a hurry in order to float to the surface, while unloading a number of dense objects might be a slow process (and could deprive the explorer of valuable gear).</p>
</>};
const _boulderhead_bock = {title: "Boulderhead bock", jsx: <><h2 id="eq-misc-boulderhead_bock-boulderhead-bock">Boulderhead bock</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 13</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Alchemical Remedies</p>
<p>This malty ale has a legendarily thick, creamy head. It creates a pleasant buzz and sense of euphoria that dull the effects of pain and concussions, granting the drinker a +1 alchemical bonus on saving throws to avoid becoming dazed, staggered, or stunned, or against any effect with the pain descriptor for 1 hour. In addition, a dose of boulderhead bock grants the drinker 1d6 temporary hit points that apply exclusively against nonlethal damage. Multiple doses of boulderhead bock stack, to a maximum alchemical bonus of +5 and a maximum of 20 temporary hit points.</p>
<p><strong><Link to="/rule/spontaneous_alchemy">Spontaneous Alchemy</Link> Recipe</strong> (4 gold + 15 spirit of wine)/fermentation; <strong>Craft DC</strong> 19<br/><strong>Time</strong> 1 week; <strong>Tools</strong> <Link to="/eq-misc/brewers_kit">brewer's kit</Link>; <strong>Type</strong> alcohol</p>
</>};
const _bounty_hunters_kit_common = {title: "Bounty hunter's kit (common)", jsx: <><h2 id="eq-misc-bounty_hunters_kit_common-bounty-hunters-kit">Bounty hunter's kit</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 20</Link><br/><strong>Price</strong> 105 gp (common), 380 gp (superior); <strong>Weight</strong> 15 lbs. (common), 24 lbs. (superior)</p>
<p>This kit provides useful tools for bounty hunters. It includes basic maps showing major landmarks, <Link to="/eq-misc/caltrops">caltrops</Link>, <Link to="/eq-misc/common_manacles">common manacles</Link> with an <Link to="/eq-misc/average_lock">average lock</Link>, a <Link to="/eq-weapon/net">net</Link>, a <Link to="/eq-weapon/sap">sap</Link>, and a 10-foot <Link to="/eq-misc/chain">chain</Link>. Bounty hunters are notoriously individualistic, so variant kits are common. One such variant is the superior bounty hunter's kit, which replaces the common manacles with <Link to="/eq-misc/masterwork_manacles">masterwork manacles</Link> and the average lock with a <Link to="/eq-misc/good_lock">good lock</Link>, and includes a <Link to="/eq-misc/footprint_book">footprint book</Link>, a <Link to="/eq-weapon/tanglefoot_bag">tanglefoot bag</Link>, and <Link to="/eq-misc/masterwork_thieves_tools">masterwork thieves' tools</Link>.</p>
</>};
const _bowling_set = {title: "Bowling set", jsx: <><h2 id="eq-misc-bowling_set-bowling-set">Bowling set</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 92</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 5 sp-10 gp; <strong>Weight</strong> 15 lbs.<br/><strong>Category</strong> Entertainment</p>
<p>This simple 10-pins game is often complicated by irregularities in the ball, the pins, and the playing field.</p>
</>};
const _braille_bracelet = {title: "Braille bracelet", jsx: <><h2 id="eq-misc-braille_bracelet-braille-bracelet">Braille bracelet</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 202</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>This bracelet contains 10 small clay beads, each carved with a raised symbol. The beads can be removed from the bracelet cord and rearranged in any order. Once arranged, the carvings can be felt with the fingers to determine the symbols' meaning and decipher any message the bracelet is meant to convey. A single bead could impart a simple message, or multiple beads can be strung together to form more complicated messages. Interpreting the beads allows individuals to communicate in absolute silence, even in complete darkness or otherwise unable to see. To use the beads properly, you and your allies must assign each bead a meaning prior to using the bracelet in this way. Recalling the meaning of a single bead requires a successful DC 10 Intelligence check. Conveying more complicated messages increases this check by 2 for each additional bead used. Deciphering the message is practically impossible for a creature that doesn't know the meanings assigned to the beads, increasing the DC by 20.</p>
</>};
const _branding_iron_common = {title: "Branding iron (common)", jsx: <><h2 id="eq-misc-branding_iron_common-branding-iron">Branding iron</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 96</Link>, <Link to="/source/path_of_the_hellknight">Path of the Hellknight pg. 63</Link><br/><strong>Price</strong> 2 gp (common), 10 gp (custom shape); <strong>Weight</strong> 5 lbs. (common), 5 lbs. (custom shape)</p>
<p>This length of bare metal is 2 to 4 feet long. One end serves as a handle, while the other forms a simple shape, such as a square or circle. Branding irons with ends that form complex symbols, such as the symbol of a Hellknight order, are much more expensive.</p>
<p>If the branding iron is heated in an open fire for 10 minutes or more, it becomes red hot. If it is pressed against wood, leather, skin, or another surface capable of being scorched, it deals 1 point of fire damage, leaving behind a burn mark that becomes a mundane scar of the branding iron's symbol. A willing or <Link to="/misc/helpless">helpless</Link> creature can be marked with a hot branding iron. If employed as an <Link to="/misc/improvised_weapon">improvised weapon</Link> in combat, a hot branding iron deals damage and leaves behind its symbol on any creature struck. If the wielder is trying to mark a particular spot on a target creature, she takes a -4 penalty on her attack roll (in addition to any penalties from using improvised weapons). Creatures immune or resistant to fire damage cannot be marked by a branding iron. A hot branding iron loses its heat quickly. It can mark only one creature within 5 minutes of being removed from a fire before it needs to be reheated.</p>
</>};
const _brawlers_brew = {title: "Brawler's brew", jsx: <><h2 id="eq-misc-brawlers_brew-brawlers-brew">Brawler's brew</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 22</Link><br/><strong>Price</strong> 150 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Tincture</p>
<p>This tincture is made of thick syrup dissolved in potent alcohol. For 1 hour after drinking this tincture, you gain DR 1/slashing or piercing and can ignore pain effects. This numbing of your body causes you to take a -2 penalty on Fortitude saving throws for the same duration.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _brawlers_kit = {title: "Brawler's kit", jsx: <><h2 id="eq-misc-brawlers_kit-brawlers-kit">Brawler's kit</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 203</Link><br/><strong>Price</strong> 9 gp; <strong>Weight</strong> 36-1/2 lbs.<br/><strong>Category</strong> Kits</p>
<p>This kit includes a <Link to="/eq-misc/backpack">backpack</Link>, a <Link to="/eq-misc/bedroll">bedroll</Link>, a <Link to="/eq-misc/belt_pouch">belt pouch</Link>, a <Link to="/eq-misc/flint_and_steel">flint and steel</Link>, <Link to="/eq-misc/rope">rope</Link>, <Link to="/eq-misc/torches">torches</Link> (10), <Link to="/eq-misc/trail_rations">trail rations</Link> (5 days), and a <Link to="/eq-misc/waterskin">waterskin</Link>.</p>
</>};
const _bread = {title: "Bread", jsx: <><h2 id="eq-misc-bread-bread">Bread</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 95</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 159</Link><br/><strong>Price</strong> 2 cp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Food/Drink</p>
<p>This is a loaf of bread with a crust that ranges from crisp to soft, depending on the local ingredients and baking methods. Bread may be leavened or unleavened, depending on whether yeast is used to make it rise. Unleavened bread is also known as flatbread, and ranges in thickness from that of a cracker to half an inch thick. Both leavened and unleavened bread may be stuffed with cheese, fruit, olives, meat, or other rich ingredients when prepared for festive occasions. Bread that is left exposed to air become dry and stale in about a day.</p>
</>};
const _breakaway_chains = {title: "Breakaway chains", jsx: <><h2 id="eq-misc-breakaway_chains-breakaway-chains">Breakaway chains</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 65 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>These masterwork chains are easy to break, even though they look like normal chains (Perception DC 25 to notice the difference). A DC 10 Strength check breaks them instantly.</p>
</>};
const _breakers_kit = {title: "Breaker's kit", jsx: <><h2 id="eq-misc-breakers_kit-breakers-kit">Breaker's kit</h2>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook pg. 7</Link><br/><strong>Price</strong> 353 gp; <strong>Weight</strong> 40 lbs.<br/><strong>Category</strong> Kits</p>
<p>This kit contains all manner of items useful for smashing down doors, creating diversions, and blowing things up. It includes a dose of <Link to="/eq-misc/alchemical_glue">alchemical glue</Link>, a flask of <Link to="/eq-weapon/alchemists_fire">alchemist's fire</Link>, a <Link to="/eq-misc/crowbar">crowbar</Link>, a <Link to="/eq-misc/drill">drill</Link>, a <Link to="/eq-weapon/fuse_grenade">fuse grenade</Link>, a <Link to="/eq-misc/glass_cutter">glass cutter</Link>, a <Link to="/eq-misc/jetcaster">jetcaster</Link>, a vial of <Link to="/eq-misc/phosphorescent_gel">phosphorescent gel</Link>, 4 pints of <Link to="/eq-misc/oil">oil</Link>, a <Link to="/eq-misc/portable_ram">portable ram</Link>, a dose of <Link to="/eq-misc/rusting_powder">rusting powder</Link>, 5 <Link to="/eq-misc/tindertwig">tindertwigs</Link>, and a <Link to="/eq-misc/wire">wire</Link>.</p>
</>};
const _breathing_tube = {title: "Breathing tube", jsx: <><h2 id="eq-misc-breathing_tube-breathing-tube">Breathing tube</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 128</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 1/10 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This simple, hollow tube roughly as long as the user's forearm is typically made to resemble a specific type of aquatic foliage, so that its user remains inconspicuous while underwater. Using a breathing tube, an air-breathing creature can stay fully submerged under water indefinitely, as long as it remains near enough to the surface of the water for the tube to reach the air.</p>
</>};
const _brewers_kit = {title: "Brewer's kit", jsx: <><h2 id="eq-misc-brewers_kit-brewers-kit">Brewer's kit</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 13</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> 50 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>A brewer's kit includes a mash tun, as well as copper kettles and piping for boiling and cooling before casking it and allowing it to ferment. It also includes a variety of dried hops and spices for flavoring.</p>
</>};
const _brewers_kit_masterwork = {title: "Brewer's kit, masterwork", jsx: <><h2 id="eq-misc-brewers_kit_masterwork-brewers-kit-masterwork">Brewer's kit, masterwork</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 13</Link><br/><strong>Price</strong> 75 gp; <strong>Weight</strong> 50 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This exceptionally crafted kit provides extra spices, a wider variety of herbs, and higher quality tools than a normal brewer's kit. A masterwork brewer's kit grants a +2 circumstance bonus on Craft (alchemy) checks to produce alcoholic beverages.</p>
</>};
const _broadsheet = {title: "Broadsheet", jsx: <><h2 id="eq-misc-broadsheet-broadsheet">Broadsheet</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 50</Link><br/><strong>Price</strong> 6 sp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>Most broadsheets circulate the latest news in the city where they were printed. Most cities in technologically developed nations with printing presses have multiple wealthy or government-backed publishers that put out broadsheets. A broadsheet typically provides information as if the reader had attempted a Diplomacy check to gather information about the topic of the broadsheet (usually news of current politics, scandals, or business) and the result of the check were 10. Rather than 1d4 hours, gathering information in this way takes only as long as is required to read the broadsheet. Broadsheets printed with engraved-plate printing presses are at least a few weeks out of date, but those printed with movable-type presses can contain news from as recently as yesterday.</p>
</>};
const _bronze_gong_irori = {title: "Bronze gong", jsx: <><h2 id="eq-misc-bronze_gong_irori-bronze-gong">Bronze gong</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_of_balance">Faiths of Balance pg. 24</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Channel Foci<br/><strong>Deity</strong> Irori</p>
<p>When activated, this small masterwork metal gong remains charged with power for 8 hours. When the gong is struck softly, it emits a clear and pleasing tone that instantly focuses the striker's thoughts and mental energy. If the creature striking the gong has a ki pool and worships <Link to="/faith/irori">Irori</Link>, she regains 1 ki point. This use expends the power within the gong.</p>
</>};
const _brooch = {title: "Brooch", jsx: <><h2 id="eq-misc-brooch-brooch">Brooch</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 89</Link><br/><strong>Price</strong> Varies; <strong>Weight</strong> -<br/><strong>Category</strong> Clothing</p>
<p>This is a small ornament used to hold an element of clothing, such as a cloak or cape, in place. Many organizations provide special brooches as a symbol of membership or to honor a special achievement.</p>
</>};
const _bucket = {title: "Bucket", jsx: <><h2 id="eq-misc-bucket-bucket">Bucket</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 5 sp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>A typical bucket has a rope handle and can hold 1-2 gallons of liquid.</p>
</>};
const _bufo_jug = {title: "Bufo (jug)", jsx: <><h2 id="eq-misc-bufo_jug-bufo-jug">Bufo (jug)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 95</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Food/Drink</p>
<p>This drink is a favorite of goblins, boggards, and other primitive humanoids. It is made by soaking a poisonous toad or frog (or its eggs) in weak beer, or by "milking" these animals for their poison and mixing it with the beer (which allows the animal to be used over and over again). Some tribes use wide-mouthed jugs and leave the dead animal inside as a crunchy treat for eating once the drink is gone. A creature drunk on bufo has the <Link to="/misc/dazzled">dazzled</Link> condition in addition to the normal intoxication effect.</p>
</>};
const _bullseye_lantern = {title: "Bullseye lantern", jsx: <><h2 id="eq-misc-bullseye_lantern-bullseye-lantern">Bullseye lantern</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 12 gp (normal), 17 gp (waterproof); <strong>Weight</strong> 3 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>A bullseye lantern provides normal light in a 60-foot cone and increases the <Link to="/rule/light_level">light level</Link> by one step in the area beyond that, out to a 120-foot cone (darkness becomes dim light and dim light becomes normal light). A bullseye lantern does not increase the light level in normal light or bright light. A lantern burns for 6 hours on 1 pint of <Link to="/eq-misc/oil">oil</Link>. You can carry a lantern in one hand.</p>
<p><strong>Waterproof Lantern:</strong> Meant to shelter its flame from both water and wind, this lantern treats severe winds as strong winds, windstorms as severe winds, and hurricanes as windstorms for the purpose of determining whether they extinguish its flame. It holds enough air to burn underwater for 5 rounds before going dark.</p>
</>};
const _bunk = {title: "Bunk", jsx: <><h2 id="eq-misc-bunk-bunk">Bunk</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 19</Link><br/><strong>Price</strong> 5 cp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Tools</p>
<p>Bunk is a slang term for fillers used to dilute drugs that are proffered as pure-grade narcotics. A drug mixed with bunk is less potent; its effects last 1d6 &times; 10 minutes for each hour they would normally last. The presence of bunk can be detected with a successful Craft (alchemy) check (DC equal to the drug manufacturer's Craft [alchemy] check - 10).</p>
<p>The duration and intensity of the drug's harmful after-effects and ability damage are not reduced, as the additives in bunk are often toxic or dangerous in their own right. When a creature takes a dose of a drug containing bunk, the creature must attempt a Fortitude save (DC 10 + 1d10). Failure causes the creature to become <Link to="/misc/sickened">sickened</Link> for 1d4 hours and take 1d2 points of ability damage to a random ability score.</p>
<p><strong><Link to="/rule/spontaneous_alchemy">Spontaneous Alchemy</Link> Recipe</strong> (1 salt + 1 urea)/filtration; <strong>Craft DC</strong> 15<br/><strong>Time</strong> 10 minutes; <strong>Tools</strong> <Link to="/eq-misc/filter">filter</Link>; <strong>Type</strong> alchemical tool</p>
</>};
const _buoy_common = {title: "Buoy (common)", jsx: <><h2 id="eq-misc-buoy_common-buoy">Buoy</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 181</Link><br/><strong>Price</strong> 5 sp (common), 10 gp (superior); <strong>Weight</strong> 16 lbs. (common), 30 lbs. (superior)</p>
<p>A buoy is used to mark a specific spot in a lake, river, or similar body of water, making it possible for you to return to that location at a later date. A common buoy includes a float (typically an air-filled bladder or sealed gourd), a 200-foot length of twine, and a 15-pound stone used as an anchor. The float is usually painted a vivid color, and may have a small flag to attract attention. Though anchor buoys prove quite resilient to normal weather and tides, they offer little challenge to intelligent creatures determined to sabotage them. A superior buoy has a spherical or ovoid hollow metal float (typically copper), a length of chain rather than twine, and a metal anchor rather than a weight.</p>
</>};
const _buoyant_balloon = {title: "Buoyant balloon", jsx: <><h2 id="eq-misc-buoyant_balloon-buoyant-balloon">Buoyant balloon</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 103</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This fist-sized alchemically treated animal bladder is tightly sealed around a small wooden grip. By giving the handle a sharp twist you break a tiny glass ampoule just inside the bladder, filling the bag with buoyant gas and causing it to swell into a 3-foot-diameter sphere. Inflating the balloon is a move action. Once filled, the balloon floats upward at a speed of 60 feet per round. The balloon can lift up to 20 pounds of weight as it rises, though carrying more than 10 pounds reduces its speed to 30 feet per round. Multiple balloons attached to a single object add their carrying capacities together when determining how much weight they can lift. If a balloon is not held or bound in place in some manner, it continues to rise until it reaches a height of 600 feet, or until 10 minutes have passed, after which it pops or deflates and is destroyed.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 15</p>
</>};
const _burglars_outfit = {title: "Burglar's outfit", jsx: <><h2 id="eq-misc-burglars_outfit-burglars-outfit">Burglar's outfit</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 20</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Clothing</p>
<p>This outfit consists of fitted pants, a shirt, a hooded reversible cloak, soft leather boots, and a face mask, all in dark or neutral colors. The outfit's few buttons and rivets are wrapped in dull, dark cloth to avoid jingling or reflecting light. A number of loops and shallow pockets are also worked into the outfit, providing ample spaces for stashing small tools or weapons.</p>
<p><strong>Tear-away clothing</strong><br/><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 89</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> +5 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Clothing</p>
<p>Sneaks and thieves know the value of a good disguise. The ability to remove that disguise in a hurry, thus revealing the next layer of disguise, is nearly as valuable. Tear-away clothing is generally loose fitting and allows another layer of clothing to be worn underneath. The seams on this clothing are designed to break easily, making it a simple matter (a standard action) to remove these items and walk away with none the wiser. Any outfit can be crafted as tear-away clothing for an additional price.</p>
</>};
const _burglars_torc = {title: "Burglar's torc", jsx: <><h2 id="eq-misc-burglars_torc-burglars-torc">Burglar's torc</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 20</Link><br/><strong>Price</strong> 2,102 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Black Market</p>
<p>Appearing as a heavy, elaborate neckpiece while worn, a burglar's torc can be removed and disassembled into its component parts in 4 minutes (or in 1 minute if the user is trained in the Disable Device skill). When dismantled, a burglar's torc contains parts that function as a set of <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-misc/masterwork_thieves_tools">masterwork thieves' tools</Link>, 10 feet of <Link to="/eq-misc/silk_rope">silk rope</Link>, and a <Link to="/eq-misc/mithral_grappling_hook">mithral grappling hook</Link>. Reassembling the torc takes 8 minutes (or 4 minutes if the user is trained in the Disable Device skill). An observer must succeed at a DC 30 Perception check to recognize an assembled burglar's torc for what it is; if the observer handles the torc, the DC for this check decreases to 15.</p>
</>};
const _burner = {title: "Burner", jsx: <><h2 id="eq-misc-burner-burner">Burner</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands pg. 28</Link><br/><strong>Price</strong> 3 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>A burner is a metal or ceramic cylinder, open at the top and perforated with air holes along the sides, often with sliding vents to open or close these apertures as the fire inside requires. A burner is used to burn fuel pellets at night without giving off light that would reveal the user's position to unfriendly eyes in the wide, empty desert lands. In places where charcoal is a popular fuel, burners are made of heavier-gauge metal. Lit coals can be banked with ashes and kept hot, either for later ignition or simply so the burner can serve as an improvised radiant heater.</p>
</>};
const _butterfly_net = {title: "Butterfly net", jsx: <><h2 id="eq-misc-butterfly_net-butterfly-net">Butterfly net</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 181</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>One end of this 6-foot-long pole supports a wide metal hoop covered by a thin mesh net. You can use this to sift objects from material capable of passing through the net, such as sand or water. You can also use a butterfly net to capture Fine or Diminutive creatures as if it were a <Link to="/eq-weapon/net">net</Link> (weapon), though you don't need to re-fold the butterfly net if you miss, and you use the handle of the butterfly net like you would the rope of a net weapon.</p>
</>};
const _cage = {title: "Cage", jsx: <><h2 id="eq-misc-cage-cage">Cage</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 81</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 185</Link><br/><strong>Price</strong> 10 gp (Diminutive or Fine), 2 gp (Tiny), 15 gp (Small or Medium), 30 gp (Large), 60 gp (Huge); <strong>Weight</strong> 2 lbs. (Diminutive or Fine), 5 lbs. (Tiny), 60 lbs. (Small or Medium), 240 lbs. (Large), 960 lbs. (Huge)</p>
<p>This secure, portable enclosure is used to hold creatures - generally animals, but a large enough cage can hold anything. Cages are made from iron, wood, or bamboo, depending on local customs and available materials. One cage holds one animal of that size, or five animals of a smaller size. The weight of the creature adds to the weight of the cage. Cages come in the following sizes: Diminutive or Fine, Tiny, Small, Medium, Large, and Huge.</p>
<p>Cages for aquatic creatures cost twice as much, and weigh four times the normal weight when filled with water.</p>
</>};
const _calistrias_kindness = {title: "Calistria's kindness", jsx: <><h2 id="eq-misc-calistrias_kindness-calistrias-kindness">Calistria's kindness</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 50</Link><br/><strong>Price</strong> 3 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Remedies</p>
<p>This tonic reduces menstrual pains and dramatically reduces the chances of conception during sexual intercourse if taken daily for 1 month. The effects last as long as it is taken daily thereafter. Each bottle contains 30 doses. Crafting it requires a successful DC 20 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _caltrops = {title: "Caltrops", jsx: <><h2 id="eq-misc-caltrops-caltrops">Caltrops</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>A caltrop is a four-pronged metal spike crafted so that one prong always faces up no matter how the caltrop comes to rest. You scatter caltrops on the ground in the hope that your enemies step on them or are at least forced to slow down to avoid them. One 2-pound bag of caltrops covers an area 5 feet square.</p>
<p>Each time a creature moves into an area covered by caltrops (or spends a round fighting while standing in such an area), it runs the risk of stepping on one. Make an attack roll for the caltrops (base attack bonus +0) against the creature. For this attack, the creature's shield, armor, and deflection bonuses do not count. If the creature is wearing shoes or other footwear, it gets a +2 armor bonus to AC. If the attack succeeds, the creature has stepped on a caltrop. The caltrop deals 1 point of damage, and the creature's speed is reduced by half because its foot is wounded. This movement penalty lasts for 24 hours, until the creature is successfully treated with a DC 15 Heal check, or until it receives at least 1 point of magical healing. A charging or running creature must immediately stop if it steps on a caltrop. Any creature moving at half speed or slower can pick its way through a bed of caltrops with no trouble.</p>
<p>Caltrops may not work against unusual opponents.</p>
</>};
const _caltrops_cold_iron = {title: "Caltrops, cold iron", jsx: <><h2 id="eq-misc-caltrops_cold_iron-caltrops-cold-iron">Caltrops, cold iron</h2>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook pg. 18</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>Cold iron caltrops function in all ways as ordinary <Link to="/eq-misc/caltrops">caltrops</Link> except that they are made of cold iron, and affect creatures with DR/cold iron accordingly.</p>
</>};
const _caltrops_vicious = {title: "Caltrops, vicious", jsx: <><h2 id="eq-misc-caltrops_vicious-caltrops-vicious">Caltrops, vicious</h2>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion pg. 12</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 4 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>These specially modified <Link to="/eq-misc/caltrops">caltrops</Link> have clusters of needle-sharp spines that are slightly longer and more brittle than those on normal caltrops. Like standard caltrops, a 2-pound bag of vicious caltrops covers a 5-foot-square area. Vicious caltrops work just like normal caltrops, save that they have an attack bonus of +4, do 1d2 points of damage, and require a DC 20 Heal check to fully treat.</p>
</>};
const _calumet = {title: "Calumet", jsx: <><h2 id="eq-misc-calumet-calumet">Calumet</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 203</Link><br/><strong>Price</strong> 20 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>A calumet is a two-piece ceremonial smoking pipe with a bowl shaped from stone or clay and an intricately carved wooden stem decorated with dangling fetishes. The pipe is typically carried in a special leather pouch festooned with beads, patterns, and trinkets. The pipe is used to smoke various herbal mixtures required for certain rituals. The communal smoking of a calumet is sometimes incorporated into diplomatic meetings as a sign of solidarity between various parties. You gain a +1 circumstance bonus on Diplomacy checks against anyone you share your calumet with in this way.</p>
</>};
const _camel = {title: "Camel", jsx: <><h2 id="eq-misc-camel-camel">Camel</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 81</Link><br/><strong>Price</strong> 150 gp; <strong>Weight</strong> 1,500 lbs<br/><strong>Category</strong> Mounts/Pets</p>
<p>Due to their incredible endurance, these Large animals are the preferred mounts of desert-dwelling people. <Link to="/monster/camel">Camels</Link> tend to be ill-tempered beasts.</p>
</>};
const _camouflage_blanket = {title: "Camouflage blanket", jsx: <><h2 id="eq-misc-camouflage_blanket-camouflage-blanket">Camouflage blanket</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 20</Link><br/><strong>Price</strong> 12 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This large, coarse blanket covers a single square and has a multi-colored design that blends in with a specific environment type, such as underground, forests, or plains (see the ranger's <Link to="/ability/favored_terrain">Favored Terrains</Link> table). A character covered by a camouflage blanket in that blanket's matching terrain has <Link to="/rule/concealment">concealment</Link>. Such characters who are also <Link to="/rule/prone">prone</Link> gain a +2 circumstance bonus on Stealth checks. The bonus applies even when the covered character attempts a Stealth check to remain hidden after sniping with a projectile weapon.</p>
</>};
const _camouflage_lichen = {title: "Camouflage lichen", jsx: <><h2 id="eq-misc-camouflage_lichen-camouflage-lichen">Camouflage lichen</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 147</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Tools</p>
<p>Though <Link to="/race/oread">oreads</Link> with obviously stony features are rare, almost all oreads have an essentially earthen quality to their skin that makes it perfect for cultivating plant life. Where other races would be appalled at the thought of plants taking root in their flesh, oreads see it as a natural and healthy extension of their elemental nature. For this reason, oread herbalists developed several strains of moss and lichen specifically adapted to grow on their bodies. Camouflage lichen is the most common variety of these oread plants. It takes 1 minute to apply a paste of camouflage lichen spores to the skin, and an additional 24 hours for the fungus to sprout. After this time, the oread is covered in a thin green layer of living plant matter, granting her a +4 bonus on Stealth checks made in green forest and jungle environments. Red-orange and white varieties exist, providing bonuses in appropriately colored environments (red-orange among autumn leaves or in red deserts, white in snow, and so on). Camouflage lichen has a short lifespan; it withers and dies 3 days after being applied, crumbling away into harmless powder. This item only works on oreads and other creatures with rock-like bodies.</p>
</>};
const _camouflage_netting = {title: "Camouflage netting", jsx: <><h2 id="eq-misc-camouflage_netting-camouflage-netting">Camouflage netting</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 20 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This loose mesh of twine and varicolored cloth is used to disguise the presence of creatures or large objects. Camouflage netting must be manufactured to provide camouflage in a single type of terrain, such as snow, sand, forest, grass, swamp, urban, or water. When you hide under the netting in the appropriate terrain, you gain a +4 circumstance bonus on Stealth checks as long as you remain immobile and prone. Covering up with camouflage netting is a full-round action requiring a DC 10 Survival check (failure means you do not cover yourself correctly with the netting and do not gain its bonus on Stealth checks). You have the <Link to="/rule/entangled">entangled</Link> condition when using the netting, except your Dexterity penalty does not affect your initiative or Stealth checks. Taking off camouflage netting is a move action, or a swift action if combined with a move action to stand up from a prone position.</p>
<p>You may spend 1 minute covering an object with camouflage netting. Make a Survival check with a -10 penalty and use the total as the Stealth check result for the object. Creatures who fail a Perception check against this Stealth DC do not recognize what the object is and usually treat it as a natural part of the terrain. For example, you can conceal a wagon as a rock or patch of brush. Covering a Large object requires two nets. Covering a Huge or Gargantuan object requires five nets and takes 10 minutes of work, and the Survival check penalty is -20 instead of -10. Camouflaging a Colossal object depends on its shape but generally requires at least 10 camouflage nets and takes 1 hour of work, and the Survival check penalty is -30 instead of -10.</p>
<p>A creature with the <Link to="/umr/scent">scent</Link> ability ignores the effect of camouflage netting and makes checks against your actual Stealth roll when in scent range. Any creature within 10 feet of a Large or larger object hidden by camouflage netting automatically recognizes it as an object covered in camouflage.</p>
</>};
const _camouflaged_canvas = {title: "Camouflaged Canvas", jsx: <><h2 id="eq-misc-camouflaged_canvas-camouflaged-canvas">Camouflaged Canvas</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 242</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This heavy cloth is dyed to match a single terrain type (chosen from the ranger's list of <Link to="/ability/favored_terrain">favored terrains</Link>). This canvas can be stretched over an area to obfuscate it from creatures wandering by. Creatures unaware of the setup must succeed at a DC 14 Perception check to realize the covered area is actually a canvas sheet. A camouflaged canvas is not waterproof, but it can be treated with oil, resin, or wax to make it water resistant.</p>
<p>Price and weight are for 1 square yard of canvas.</p>
</>};
const _campsite_kit = {title: "Campsite kit", jsx: <><h2 id="eq-misc-campsite_kit-campsite-kit">Campsite kit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 12 gp; <strong>Weight</strong> 80 lbs.<br/><strong>Category</strong> Kits</p>
<p>This kit is actually four bundles of gear, designed so four individuals can share the load. It consists of four <Link to="/eq-misc/bedroll">bedrolls</Link>, four <Link to="/eq-misc/blanket">blankets</Link>, a day's worth of <Link to="/eq-misc/firewood">firewood</Link>, a <Link to="/eq-misc/flint_and_steel">flint and steel</Link>, a <Link to="/eq-misc/tindertwig">tindertwig</Link>, four <Link to="/eq-misc/mess_kit">mess kits</Link>, a <Link to="/eq-misc/cooking_kit">cooking kit</Link>, and 8 days of <Link to="/eq-misc/trail_rations">trail rations</Link> (with the expectation that adventurers will supplement the rations with a little hunting as they travel). Adventurers expecting inclement weather should also purchase one or more <Link to="/eq-misc/tent">tents</Link>.</p>
</>};
const _canary = {title: "Canary", jsx: <><h2 id="eq-misc-canary-canary">Canary</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 4 cp; <strong>Weight</strong> 9 oz.<br/><strong>Category</strong> Mounts/Pets</p>
<p>These Diminutive birds usually have bright feathers and sing pleasantly. More pragmatically, they are also used in mines to detect bad air, as their small bodies are more sensitive to such things; the warning they provide gives humanoids a chance to escape before succumbing to the danger.</p>
</>};
const _candle_lamp = {title: "Candle lamp", jsx: <><h2 id="eq-misc-candle_lamp-candle-lamp">Candle lamp</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>A candle lamp is a small lantern-like device with glass panels and a slot to hold a <Link to="/eq-misc/candle">candle</Link>. It protects the candle from drafts and catches wax drippings. It provides the same light as a candle, but can be shuttered such that it only illuminates 1 to 3 adjacent squares. You can use a candle lamp to keep your hands warm.</p>
</>};
const _candle = {title: "Candle", jsx: <><h2 id="eq-misc-candle-candle">Candle</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 1 cp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>A candle dimly illuminates a small area, increasing the <Link to="/rule/light_level">light level</Link> in a 5-foot radius by one step (darkness becomes dim light and dim light becomes normal light). A candle cannot increase the light level above normal light. A candle burns for 1 hour.</p>
</>};
const _candlefish = {title: "Candlefish", jsx: <><h2 id="eq-misc-candlefish-candlefish">Candlefish</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 26</Link><br/><strong>Price</strong> 7 sp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Food/Drink</p>
<p>This long, oily, salted fish comes strung on a wick similar to that found in a candle. The fish can be cooked and eaten as a tasty trail ration, with the listed price buying a fish big enough for one day's worth of food for a single creature. As long as the fish stays dry, it can go for months without spoiling. Sections of the candlefish can also be burned as a candle. One day's worth of candlefish is equivalent to six candles. Once used as a candle, a candlefish can no longer be eaten.</p>
</>};
const _candlerod = {title: "Candlerod", jsx: <><h2 id="eq-misc-candlerod-candlerod">Candlerod</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 103</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>Similar to but weaker than a <Link to="/eq-misc/sunrod">sunrod</Link>, this stick glows like a candle when struck and lasts for 12 hours.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _candlestick = {title: "Candlestick", jsx: <><h2 id="eq-misc-candlestick-candlestick">Candlestick</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 1 cp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This saucer-like object has a flat bottom, a handle, and a spike on top. You can affix a <Link to="/eq-misc/candle">candle</Link> onto the spike (up to 3 inches in diameter) and hold the candlestick by the handle. The flat bottom means you're able to set it down and not worry about the candle falling over and extinguishing itself. A typical candlestick is crafted from baked clay or a cheap metal such as copper, but elaborate and expensive ones exist.</p>
</>};
const _cane_common = {title: "Cane (common)", jsx: <><h2 id="eq-misc-cane_common-cane">Cane</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 12</Link><br/><strong>Price</strong> 1 sp (common), 25 gp (elegant), 2 gp (simple); <strong>Weight</strong> 3 lbs. (common), 4 lbs. (elegant), 3 lbs. (simple)</p>
<p>A cane is a walking stick fashioned from wood. A cane sports either a metal cap or a curved top that's easy to grip. Simple canes are no more than a sturdy branch, while high quality canes are made from fine materials and bear intricate carvings or adornments.</p>
</>};
const _cane_hollow_common = {title: "Cane, hollow (common)", jsx: <><h2 id="eq-misc-cane_hollow_common-cane-hollow">Cane, hollow</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 12</Link><br/><strong>Price</strong> +1 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>A hollow cane has a false top that conceals a small compartment within the cane. The compartment is large enough to house a potion or vial. Spotting the secret compartment of a hollow cane requires a successful DC 18 Perception check.</p>
</>};
const _cannon_ball = {title: "Cannon ball", jsx: <><h2 id="eq-misc-cannon_ball-cannon-ball">Cannon ball</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 293</Link><br/><strong>Price</strong> 30 gp; <strong>Weight</strong> 25 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>A cannon ball is the ammunition of a <Link to="/eq-siegeengine/cannon">cannon</Link> and many other siege firearms. Picking up or drawing a cannon ball requires a move action for Medium and Small creatures, but is a free action for Large and larger creatures.</p>
</>};
const _canteen = {title: "Canteen", jsx: <><h2 id="eq-misc-canteen-canteen">Canteen</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This hollow container is made of wood, a gourd, or metal, and carries liquid like a <Link to="/eq-misc/waterskin">waterskin</Link>, but is more resistant to punctures and cuts.</p>
</>};
const _canvas_sq_yd = {title: "Canvas (sq. yd.)", jsx: <><h2 id="eq-misc-canvas_sq_yd-canvas-sq-yd">Canvas (sq. yd.)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 1 sp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This square yard of heavy cloth is suitable for painting, for covering items in a rainstorm, for creating a sail, or as an improvised bag. It is not waterproof but can be treated with oil, wax, or resin to make it water-resistant.</p>
</>};
const _caparison = {title: "Caparison", jsx: <><h2 id="eq-misc-caparison-caparison">Caparison</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 14</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 4 lbs.<br/><strong>Category</strong> Animal Gear</p>
<p>A caparison is a sizable cloth covering laid over a mount or other four-legged creature. It serves many of the same purposes a cloak does for a humanoid creature, occupies the shoulder slot, and can be enchanted in the same manner. Caparisons are sometimes made of precious materials or crafted with delicate artistry - this does not increase their practicality, but can significantly increase their price as art objects.</p>
</>};
const _caphorite_dust = {title: "Caphorite dust", jsx: <><h2 id="eq-misc-caphorite_dust-caphorite-dust">Caphorite dust</h2>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion pg. 29</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This small leather pouch is filled with a faintly radioactive ore called <Link to="/eq-material/caphorite">caphorite</Link>, with a small percentage of reactants that activate the dust. When used, caphorite dust must be sprinkled in a 5-foot square, which then becomes the center of the dust's effect. All bright or normal light within 30 feet of the activated dust is reduced to <Link to="/rule/dim_light">dim light</Link>, and any creature attempting to cast a spell with the light descriptor in this area must succeed at a DC 15 caster level check or have spell's effect be negated. If caphorite is exposed to sunlight, it immediately becomes permanently inert. Each pouch contains enough dust for two applications. Crafting this item requires a successful DC 25 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 25</p>
</>};
const _caravan_masters_wagon = {title: "Caravan master's wagon", jsx: <><h2 id="eq-misc-caravan_masters_wagon-caravan-masters-wagon">Caravan master's wagon</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 116</Link><br/><strong>Price</strong> 1,000 gp; <strong>Price of Passage</strong> (per mile) -<br/><strong>Category</strong> Transport, Land</p>
<p>The caravan master's wagon is similar in most respects to a high-quality heavy <Link to="/eq-misc/smugglers_wagon">smuggler's wagon</Link>, but it additionally allows for a hidden <Link to="/magic-wondrous/portable_hole">portable hole</Link> (price not included above) secreted within in it. The portable hole rests upon the surface of the wagon bed, with a second layer of wooden planks laid atop it and fastened into place with nuts and bolts so they appear to be a normal part of the wagon. Thus the portable hole sits between the layers of wood like a thin cut of meat between two slices of bread. Those who know about the portable hole can fill it with illicit goods and then fasten the second layer of decking in place and load normal cargo atop it. The wagon weighs no more than it should. This setup allows for the transport of live cargo (rendered suitably silent or unconscious, if necessary), as the planks atop the opening of the portable hole are spaced just far enough apart to allow in breathable air, if the smugglers leave the hole open and attached. Unless someone knows what to look for, a successful DC 30 Perception check is necessary to discover the hidden second layer.</p>
</>};
const _cardice_oil = {title: "Cardice oil", jsx: <><h2 id="eq-misc-cardice_oil-cardice-oil">Cardice oil</h2>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook pg. 26</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This bottle of viscous blue oil sublimates slightly when exposed to air. When poured over water, the oil pools on the surface and takes 1 round to spread out from the point of origin in a 20-foot radius. At the end of this round, the cardice oil flash-freezes the surface of the water, creating an ice sheet over the affected area. Any 5-foot square of this ice can support up to 200 pounds of weight. Weight in excess of this amount causes the entire sheet to crack and quickly break up. This ice sheet becomes unstable and breaks up on its own after 1 hour, or 20 minutes in a hot climate. Any creature whose bare skin comes in contact with cardice oil takes 1d6 points of nonlethal damage each round because of the chemical's volatile nature, but the oil is ineffective as a splash weapon.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 25</p>
</>};
const _cards = {title: "Cards", jsx: <><h2 id="eq-misc-cards-cards">Cards</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 92</Link><br/><strong>Price</strong> 1 sp-100 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Entertainment</p>
<p>Playing cards range from block-printed symbols on thick paper to elaborate, hand-painted works of art on waxed vellum, ivory, wood, or even metal.</p>
</>};
const _carnivore_feed_per_day = {title: "Carnivore feed (per day)", jsx: <><h2 id="eq-misc-carnivore_feed_per_day-carnivore-feed-per-day">Carnivore feed (per day)</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 12</Link><br/><strong>Price</strong> 5 cp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Animal Gear</p>
<p>Consisting of various kinds of raw meat that have been jerked, smoked, or salted for preservation, a day's worth of carnivore feed is adequate food for any Small or Medium meat-eating animal such as a tiger, bear, or dog. Larger carnivores might require up to 2 to 4 days' worth of carnivore feed per day.</p>
</>};
const _carriage = {title: "Carriage", jsx: <><h2 id="eq-misc-carriage-carriage">Carriage</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 87</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 159</Link><br/><strong>Price</strong> 100 gp; <strong>Price of Passage</strong> (per mile) 3 cp<br/><strong>Category</strong> Transport, Land</p>
<p>This four-wheeled vehicle can transport as many as four people within an enclosed cab, plus two drivers. In general, two horses (or other beasts of burden) draw it. A carriage comes with the <Link to="/eq-misc/harness">harness</Link> needed to pull it.</p>
</>};
const _carrion_bait = {title: "Carrion bait", jsx: <><h2 id="eq-misc-carrion_bait-carrion-bait">Carrion bait</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 11</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This large glass jar is vacuum-sealed with an airtight wax plug. Inside, festering chunks of monkey meat are covered in fungal mycelium and seeded with fly eggs, though the mixture's potency is not evident until it's exposed to air. Once the jar is opened (a standard action), the stench quickly becomes overpowering as the jar's contents swell and rot at an accelerated rate. Any living creature within 15 feet of the jar when it is opened must succeed at a DC 12 Fortitude save or be <Link to="/misc/sickened">sickened</Link> for 1d4 rounds.</p>
<p>Vermin and undead have a hard time distinguishing carrion bait from rotten human flesh, but intelligent undead that succeed at a DC 15 Perception check realize the difference. Regardless, any creature that spends more than 1 round eating the carrion bait quickly realizes its error, since the bait continues to swell and grow even as it's digested. One round after eating carrion bait, an affected undead or vermin becomes <Link to="/misc/staggered">staggered</Link> for 1d4 rounds as its belly bulges to incredible proportions (other creature types cannot stomach carrion bait and instead are <Link to="/misc/nauseated">nauseated</Link> for 2d4 rounds). If the affected creature is already staggered, its movement speed instead decreases by 10 feet for the duration of the carrion bait's effect. Crafting carrion bait requires a successful DC 19 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 19</p>
</>};
const _cart = {title: "Cart", jsx: <><h2 id="eq-misc-cart-cart">Cart</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 87</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 159</Link><br/><strong>Price</strong> 15 gp; <strong>Price of Passage</strong> (per mile) 1 cp<br/><strong>Category</strong> Transport, Land</p>
<p>This two-wheeled vehicle can be drawn by a single horse or other beast of burden, and is often used to transport goods across short distances. It comes with a <Link to="/eq-misc/harness">harness</Link>.</p>
</>};
const _casting_plaster = {title: "Casting plaster", jsx: <><h2 id="eq-misc-casting_plaster-casting-plaster">Casting plaster</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 103</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 184</Link><br/><strong>Price</strong> 5 sp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This white, dry powder mixes with water to form a paste, which hardens over the course of an hour to create a solid material. It can be used to make casts of footprints or carvings, fill in gaps or cracks in walls, or (if applied over a cloth wrapping) create a cast for a broken bone. Hardened plaster has hardness 1 and 5 hit points per inch of thickness. A 5-pound clay pot of plaster can cover about 5 square feet of flat space to a depth of 1 inch, five Medium forearm or lower-leg casts, two Medium full-arm or full-leg casts, or twice as many casts for a Small creature.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 25</p>
</>};
const _cat_common = {title: "Cat (common)", jsx: <><h2 id="eq-misc-cat_common-cat">Cat</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 80</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 3 cp (common), 6 gp (Osirian wise-eye); <strong>Weight</strong> 8 lbs. (common), 8 lbs. (Osirian wise-eye)</p>
<p>These Tiny animals are often kept as pets or familiars. Though small, they are excellent hunters. Grain farmers usually keep cats for pest control in crop storage areas, but cats can be found in most regions and strays occupy many cities.</p>
</>};
const _cat_hunting = {title: "Cat (hunting)", jsx: <><h2 id="eq-misc-cat_hunting-cat-hunting">Cat (hunting)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 80</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> 100 lbs.<br/><strong>Category</strong> Mounts/Pets</p>
<p>Rarely, Medium cats such as cheetahs and leopards are trained to hunt for humanoid masters.</p>
</>};
const _cat_burglars_kit = {title: "Cat burglar's kit", jsx: <><h2 id="eq-misc-cat_burglars_kit-cat-burglars-kit">Cat burglar's kit</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 13</Link><br/><strong>Price</strong> 15 gp; <strong>Weight</strong> 12 lbs.<br/><strong>Category</strong> Kits</p>
<p>This kit includes a <Link to="/eq-misc/glass_cutter">glass cutter</Link>, <Link to="/eq-misc/glue_paper">glue paper</Link> (5 sheets), a <Link to="/eq-misc/grappling_hook">grappling hook</Link>, a <Link to="/eq-misc/masterwork_backpack">masterwork backpack</Link>, and <Link to="/eq-misc/silk_rope_50_feet">silk rope (50 feet)</Link>.</p>
</>};
const _cattle = {title: "Cattle", jsx: <><h2 id="eq-misc-cattle-cattle">Cattle</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 81</Link><br/><strong>Price</strong> 10-50 gp; <strong>Weight</strong> 1,500 lbs.<br/><strong>Category</strong> Mounts/Pets</p>
<p>Cattle are kept for milk and meat, and used as beasts of burden. A bull is used primarily for mating. Other males are castrated and become oxen, which are used to carry loads and plow fields.</p>
</>};
const _cauim_gourd = {title: "Cauim (gourd)", jsx: <><h2 id="eq-misc-cauim_gourd-cauim-gourd">Cauim (gourd)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 95</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Food/Drink</p>
<p>This beer-like drink, made from manioc root or corn, requires extensive chewing as part of its production.</p>
</>};
const _caul = {title: "Caul", jsx: <><h2 id="eq-misc-caul-caul">Caul</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 89</Link><br/><strong>Price</strong> 10-100 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Clothing</p>
<p>This ornate hairnet, fashioned from silk, cloth of gold, and jewels, is most commonly worn by royal or aristocratic women.</p>
</>};
const _cauldron_mithral = {title: "Cauldron (mithral)", jsx: <><h2 id="eq-misc-cauldron_mithral-cauldron">Cauldron</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 1 gp, 2,501 gp (mithral); <strong>Weight</strong> 5 lbs., 2-1/2 lbs. (mithral)</p>
<p>This larger version of an iron pot holds approximately 1 gallon - enough to fill the bellies of four hungry humans for one meal. It can also be used for potion-making and similar activities. A mithral cauldron is lighter, and food rarely sticks to it.</p>
</>};
const _cavaliers_kit = {title: "Cavalier's kit", jsx: <><h2 id="eq-misc-cavaliers_kit-cavaliers-kit">Cavalier's kit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 23 gp; <strong>Weight</strong> 112 lbs.<br/><strong>Category</strong> Kits</p>
<p>This includes <Link to="/eq-misc/animal_feed">animal feed</Link> (5 days), a <Link to="/eq-misc/backpack">backpack</Link>, a <Link to="/eq-misc/bedroll">bedroll</Link>, a <Link to="/eq-misc/belt_pouch">belt pouch</Link>, a <Link to="/eq-misc/bit_and_bridle">bit and bridle</Link>, a <Link to="/eq-misc/flint_and_steel">flint and steel</Link>, an <Link to="/eq-misc/iron_pot">iron pot</Link>, a <Link to="/eq-misc/mess_kit">mess kit</Link>, a <Link to="/eq-misc/riding_saddle">riding saddle</Link>, <Link to="/eq-misc/rope">rope</Link>, <Link to="/eq-misc/saddlebags">saddlebags</Link>, <Link to="/eq-misc/soap">soap</Link>, <Link to="/eq-misc/torches">torches</Link> (10), <Link to="/eq-misc/trail_rations">trail rations</Link> (5 days), and a <Link to="/eq-misc/waterskin">waterskin</Link>.</p>
</>};
const _cave_whistle = {title: "Cave whistle", jsx: <><h2 id="eq-misc-cave_whistle-cave-whistle">Cave whistle</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 135</Link><br/><strong>Price</strong> 20 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>Fashioned from the spongy stem of a rare mushroom, this whistle produces a sound that only kobolds and dragons can hear. Kobolds often create complicated codes made up of notes that they use to coordinate ambushes and raids.</p>
</>};
const _caviar = {title: "Caviar", jsx: <><h2 id="eq-misc-caviar-caviar">Caviar</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 95</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Food/Drink</p>
<p>These translucent, salty fish eggs are a delicacy. They are usually eaten as a spread on crackers, boiled eggs, bread, pastries, or vegetables. They tend to spoil quickly and are rare outside of the coastal areas where they are harvested. Purists only consider sturgeon eggs to be true caviar, but others are more relaxed about the definition and include salmon, trout, and whitefish eggs as caviar. In some countries, the roe of larger exotic fish and sea creatures (such as <Link to="/monster/chuul">chuul</Link>, <Link to="/monster/giant_gar">giant gar</Link>, and <Link to="/monster/reefclaw">reefclaws</Link>) are eaten as caviar, though at much higher prices.</p>
</>};
const _caydenbrew_mug = {title: "Caydenbrew (mug)", jsx: <><h2 id="eq-misc-caydenbrew_mug-caydenbrew">Caydenbrew</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 5 cp/mug; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Food/Drink</p>
<p>This ale is the standard beer drunk in Absalom. The recipe was said to be the last beer <Link to="/faith/cayden_cailean">Cayden Cailean</Link> had before he undertook the Test of the Starstone. The hops for this beer were originally grown on the Isle of Kortos, but the massive brewery now imports from Andoran and Taldor.</p>
</>};
const _celestial_censer = {title: "Celestial censer", jsx: <><h2 id="eq-misc-celestial_censer-celestial-censer">Celestial censer</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 87</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 3 lbs.<br/><strong>Category</strong> Tools</p>
<p>This blessed thurible holds up to 10 pieces of <Link to="/eq-misc/incense">incense</Link>, and burns at a rate of 1 stick per hour. If a <Link to="/eq-misc/smokestick">smokestick</Link> is added to the incense in the <Link to="/eq-misc/censer">censer</Link> while it burns, creatures with the evil subtype are <Link to="/misc/dazzled">dazzled</Link> for as long as they remain within the area of the resulting smoke.</p>
</>};
const _celestial_lamp = {title: "Celestial lamp", jsx: <><h2 id="eq-misc-celestial_lamp-celestial-lamp">Celestial lamp</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 87</Link><br/><strong>Price</strong> 300 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Tools</p>
<p>This polished lantern contains a continual flame and sheds light as a common <Link to="/eq-misc/lamp">lamp</Link>. If its font of consecrated crystal and metalwork is filled with holy water, the lamp's light is sanctified for 24 hours, adding a +1 bonus to the save DC of channeled positive energy or energy channeled to harm evil outsiders within a 30-foot radius.</p>
</>};
const _celwynvian_stone_fruit = {title: "Celwynvian stone fruit", jsx: <><h2 id="eq-misc-celwynvian_stone_fruit-celwynvian-stone-fruit">Celwynvian stone fruit</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 21</Link><br/><strong>Price</strong> 500 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Food/Drink</p>
<p>This bizarre fruit appears to be carved from stone, though it has a lovely aroma and is easily consumed. Stone fruits occasionally sprout from the strange tree-like monument known as the Celwynvian Charge, where they are gathered by licensed vendors and sold to travelers. Eating a stone fruit hardens flesh and restores vitality. When a creature eats the fruit as a full-round action that provokes attacks of opportunity, it immediately recovers 2d6 hit points and gains a +2 enhancement bonus to its natural armor for 1 minute.</p>
</>};
const _censer = {title: "Censer", jsx: <><h2 id="eq-misc-censer-censer">Censer</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 248</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This metal container comes with a small removable lid, and holds a small crucible in which to burn incense. Used in religious ceremonies or rituals, a censer can hold up to 10 pieces of <Link to="/eq-misc/incense">incense</Link>, and burns 1 piece per hour when lit.</p>
</>};
const _centipede_house = {title: "Centipede (house)", jsx: <><h2 id="eq-misc-centipede_house-centipede-house">Centipede (house)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 80</Link><br/><strong>Price</strong> 1 cp; <strong>Weight</strong> 3 oz.<br/><strong>Category</strong> Mounts/Pets</p>
<p>These creatures come in many forms, from the lighter-colored 20-legged variety to the darker 300-legged variety. Typically, these arthropods are what pass for pets in the slums, but the young and eccentric often search for the best specimens to serve as familiars. Centipedes employed as familiars have an Intelligence score and lose the mindless trait.</p>
</>};
const _chain_10_ft = {title: "Chain (10 ft.)", jsx: <><h2 id="eq-misc-chain_10_ft-chain-10-ft">Chain (10 ft.)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 30 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This chain is made of interlocking metal links roughly an inch long, and thick enough to bear large amounts of weight. It has hardness 10 and 5 hit points. It can be burst with a DC 26 Strength check.</p>
</>};
const _chain_belt = {title: "Chain belt", jsx: <><h2 id="eq-misc-chain_belt-chain-belt">Chain belt</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 177</Link><br/><strong>Price</strong> 15 gp; <strong>Weight</strong> 1/4 lb.<br/><strong>Category</strong> Clothing</p>
<p>While <Link to="/race/undine">undines</Link> dress sparingly, they often wear 10-foot-long belts of fine linked chain about their waists. The belts contain hinged links to which the wearer can affix various objects such as tools, small weapons, and other valuables, including links of silver and platinum, or small hammered plates of gold set with gems. If worn properly, the belt can hold up to 30 pounds of small items. A swimming undine can unwrap the belt as swift action if she needs to remove it to decrease her weight load.</p>
</>};
const _chains_of_contrition = {title: "Chains of contrition", jsx: <><h2 id="eq-misc-chains_of_contrition-chains-of-contrition">Chains of contrition</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory">Adventurer's Armory pg. 24</Link><br/><strong>Price</strong> 200 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Channel Foci<br/><strong>Deity</strong> Any</p>
<p>Each carefully forged link of these <Link to="/eq-misc/masterwork_manacles">masterwork manacles</Link> (with a <Link to="/eq-misc/good_lock">good lock</Link>) contains a parable or other quotes excerpted from sacred texts. Activating the focus increases its Disable Device, Escape Artist, and break DCs by 5; its hardness increases by 2 and its hit points by 4. This effect lasts 24 hours or until the creature frees itself or is released.</p>
</>};
const _chalk = {title: "Chalk", jsx: <><h2 id="eq-misc-chalk-chalk">Chalk</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 1 cp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>This fat piece of white chalk easily marks wood, metal, or stone. You can write with it for about 24 hours before it is expended. Chalk also comes in other colors, but these are rarer and can be more expensive.</p>
</>};
const _chalkboard = {title: "Chalkboard", jsx: <><h2 id="eq-misc-chalkboard-chalkboard">Chalkboard</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 181</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>A wooden frame approximately the same size as a large book surrounds this thinly sliced piece of polished black stone. Rubbing a damp cloth over the slate erases anything scribed with chalk on its surface.</p>
</>};
const _chameleon_ointment = {title: "Chameleon ointment", jsx: <><h2 id="eq-misc-chameleon_ointment-chameleon-ointment">Chameleon ointment</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 15</Link><br/><strong>Price</strong> 20 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Remedies</p>
<p>When applied to a <Link to="/monster/homunculus">homunculus's</Link> skin (which takes 1 minute), this ointment causes the creature's flesh to shift color and pattern reflexively to match its surroundings. The homunculus gains a +4 circumstance bonus on Stealth checks for 24 hours. The ointment can also be applied to other creatures as long as they are Medium or smaller and wear no clothing or armor to obstruct their skin, but the bonus is reduced to +2.</p>
<p><strong><Link to="/rule/spontaneous_alchemy">Spontaneous Alchemy</Link> Recipe</strong> (1 gold + 12 silver + 12 urea)/ceration; <strong>Craft DC</strong> 20<br/><strong>Time</strong> 10 minutes; <strong>Tools</strong> <Link to="/eq-misc/crucible">crucible</Link>; <strong>Type</strong> alchemical remedy</p>
</>};
const _chameleon_pill = {title: "Chameleon pill", jsx: <><h2 id="eq-misc-chameleon_pill-chameleon-pill">Chameleon pill</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 50</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Tools</p>
<p>This pill causes the imbiber's skin to shift colors and patterns to match whatever is behind her. As long as a significant portion of her skin is exposed (her head and forearms, for example), the imbiber gains a +4 circumstance bonus on Stealth checks for 4 hours. This bonus doesn't stack with that granted by <Link to="/spell/invisibility">invisibility</Link>, <Link to="/spell/vanish">vanish</Link>, or similar magical effects. Crafting a chameleon pill requires a successful DC 15 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 15</p>
</>};
const _charcoal = {title: "Charcoal", jsx: <><h2 id="eq-misc-charcoal-charcoal">Charcoal</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 12</Link>, <Link to="/source/seekers_of_secrets">Seekers of Secrets pg. 42</Link><br/><strong>Price</strong> 5 sp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>Sticks of charcoal are useful for marking floors and walls, writing on <Link to="/eq-misc/paper">paper</Link> or <Link to="/eq-misc/parchment">parchment</Link>, and making rubbings of engravings or other markings. In a pinch, they can even be burned to stay warm. A good-quality rubbing generally takes 1 minute per sheet of paper.</p>
</>};
const _charda_claws = {title: "Charda claws", jsx: <><h2 id="eq-misc-charda_claws-charda-claws">Charda claws</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 21</Link><br/><strong>Price</strong> 150 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>This tiny set of sculpted claws, made from stone carefully chipped from the Battle of Charda monument, is set upon a fine chain. Once per day when attempting an <Link to="/skill/intimidate">Intimidate</Link> check to demoralize a single opponent in combat, the user can forcefully present the charda claws as part of the action to activate their residual power. Using the claws in this way requires a free hand, but only while the Intimidate check is made. If the Intimidate check was a success and the target is demoralized, the claws grant the wielder a +1 morale bonus on attack rolls against that creature for the duration of the demoralized effect. If the wielder uses the claws but the Intimidate check is not successful, the claws' daily use is expended to no effect.</p>
</>};
const _chariot = {title: "Chariot", jsx: <><h2 id="eq-misc-chariot-chariot">Chariot</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 87</Link><br/><strong>Price</strong> 200 gp (heavy), 50 gp (light), 100 gp (medium); <strong>Price of Passage</strong> 2 cp (heavy), 2 cp (light), 2 cp (medium)<br/><strong>Category</strong> Transport, Land</p>
<p>This two-wheeled vehicle is drawn by a horse. There are three varieties of chariots.</p>
<p><strong>Light Chariots:</strong> These chariots are often used for racing or as the platform for a single archer charging across the battlefield at high speed.</p>
<p><strong>Medium Chariots:</strong> These chariots are used in battle to break apart infantry formations or as fast-moving fighting platforms.</p>
<p><strong>Heavy Chariots:</strong> This type of chariot is typically used as a fighting platform or for transporting material quickly onto the battlefield.</p>
</>};
const _chausses = {title: "Chausses", jsx: <><h2 id="eq-misc-chausses-chausses">Chausses</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 20</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 3 lbs.<br/><strong>Category</strong> Clothing</p>
<p>These padded woolen leggings are quilted to provide extra warmth and protection. They are frequently worn under mail or plate armor.</p>
</>};
const _cheat_sheath = {title: "Cheat sheath", jsx: <><h2 id="eq-misc-cheat_sheath-cheat-sheath">Cheat sheath</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 203</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Tools</p>
<p>This ornate leather sheath is covered in tables of magical notation and arcane formulae, as well as common spell triggers and reagents. Referring to these handy bits of notation grants you a +2 circumstance bonus on Spellcraft checks made to learn a spell from a spellbook or scroll, prepare a spell from a borrowed spellbook, identify the properties of a magic item using <Link to="/spell/detect_magic">detect magic</Link>, or decipher a scroll.</p>
</>};
const _cheese = {title: "Cheese", jsx: <><h2 id="eq-misc-cheese-cheese">Cheese</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 95</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 159</Link><br/><strong>Price</strong> 1 sp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Food/Drink</p>
<p>The listed price is for a hunk of cheese from a wheel. A 5- or 10-pound wheel of aged cheese is encased in a tough rind, which keeps the interior fresh.</p>
</>};
const _chemical_ward = {title: "Chemical ward", jsx: <><h2 id="eq-misc-chemical_ward-chemical-ward">Chemical ward</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 26</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This gray paste congeals when spread onto a surface, gradually changing color to match its surroundings. When applied, its reagents bond with chemicals in the environment, exuding a magnified aura that can fool <Link to="/umr/blindsight">blindsight</Link> and <Link to="/umr/blindsense">blindsense</Link>. This affects only blindsight or blindsense based on smell, taste, vibration, and similar senses; it does not affect extraordinary sight, hearing, or <Link to="/umr/tremorsense">tremorsense</Link>. Applying a flask of chemical ward to the edge of a 5-foot square takes a full-round action, creating an opaque barrier against blindsense and blindsight that lasts for 1 hour. A creature can sense through the barrier with a successful Perception check (DC 15 for blindsight, 20 for blindsense), although individuals on the opposite side of the barrier can attempt Stealth checks against the creature's blindsight or blindsense as though they had <Link to="/rule/concealment">concealment</Link>. The barrier does not inhibit movement.</p>
</>};
const _chest_huge = {title: "Chest (huge)", jsx: <><h2 id="eq-misc-chest_huge-chest">Chest</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 181</Link><br/><strong>Price</strong> 25 gp (huge), 10 gp (large), 5 gp (medium), 2 gp (small); <strong>Weight</strong> 250 lbs. (huge), 100 lbs. (large), 50 lbs. (medium), 25 lbs. (small)</p>
<p>The common wooden chest comes in several sizes, including small (2 cubic feet, 1 hit point, break DC 17), medium (4 cubic feet, 15 hp, break DC 23), large (6 cubic feet, 30 hit points, break DC 29), and huge (8 cubic feet, 50 hit points, break DC 35). Most include a <Link to="/eq-misc/simple_lock">simple inset lock</Link>.</p>
</>};
const _chicken = {title: "Chicken", jsx: <><h2 id="eq-misc-chicken-chicken">Chicken</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 81</Link>, <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 93</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 6 lbs.<br/><strong>Category</strong> Mounts/Pets</p>
<p>These domesticated birds are not capable of long distance flights, and are raised for their eggs and meat. Male chickens are kept for mating and occasionally blood sport.</p>
</>};
const _chill_cream = {title: "Chill cream", jsx: <><h2 id="eq-misc-chill_cream-chill-cream">Chill cream</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 103</Link><br/><strong>Price</strong> 15 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This sticky light blue paste grows pleasantly cool to the touch whenever it is exposed to light. Spreading a dose on your face and hands takes a full-round action and grants you a +2 alchemical bonus on saves to resist <Link to="/rule/heat_dangers">hot weather</Link>. In areas of bright light this bonus increases to +4, while in areas of <Link to="/rule/dim_light">dim light</Link> or darkness it is negated. A dose of chill cream lasts for 1 hour after being applied. A newly crafted bottle of chill cream holds 5 doses.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 15</p>
</>};
const _chirurgeons_kit = {title: "Chirurgeon's kit", jsx: <><h2 id="eq-misc-chirurgeons_kit-chirurgeons-kit">Chirurgeon's kit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 47</Link><br/><strong>Price</strong> 400 gp; <strong>Weight</strong> 4 lbs.<br/><strong>Category</strong> Kits</p>
<p>This sturdy leather case straps to the waist or thigh, or can be slung over a shoulder. It consists of a <Link to="/eq-misc/belt_pouch">leather pouch</Link>, a <Link to="/eq-misc/healers_kit">healer's kit</Link>, a bottle of strong <Link to="/eq-misc/whiskey">brandy</Link>, a potion of <Link to="/spell/cure_light_wounds">cure light wounds</Link>, a vial of <Link to="/eq-misc/smelling_salts">smelling salts</Link>, and 2 doses each of <Link to="/eq-misc/alchemists_kindness">alchemist's kindness</Link>, <Link to="/eq-misc/antiplague">antiplague</Link>, <Link to="/eq-misc/antitoxin">antitoxin</Link>, <Link to="/eq-misc/bloodblock">bloodblock</Link>, and <Link to="/eq-misc/soothe_syrup">soothe syrup</Link>.</p>
</>};
const _chocolate_bar = {title: "Chocolate (bar)", jsx: <><h2 id="eq-misc-chocolate_bar-chocolate-bar">Chocolate (bar)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 95</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Food/Drink</p>
<p>This dark, bitter treat can be consumed as a solid or melted and added to a beverage such as milk. In some lands it is mixed with sugar or chilies.</p>
</>};
const _chroniclers_kit = {title: "Chronicler's kit", jsx: <><h2 id="eq-misc-chroniclers_kit-chroniclers-kit">Chronicler's kit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 47</Link><br/><strong>Price</strong> 40 gp; <strong>Weight</strong> 4-1/2 lbs.<br/><strong>Category</strong> Kits</p>
<p>This bundle contains a map case, two vials of <Link to="/eq-misc/ink">ink</Link>, two <Link to="/eq-misc/inkpen">inkpens</Link>, 10 sheets of <Link to="/eq-misc/paper">paper</Link>, two blank <Link to="/eq-misc/journal">journals</Link>, a pound of fine <Link to="/eq-misc/powder">powder</Link> for drying ink, and a 20-foot <Link to="/eq-misc/measuring_cord">measuring cord</Link>. The supplies usually suffice for chronicling a single expedition of not more than 2 months' duration.</p>
</>};
const _cipher_rings = {title: "Cipher rings", jsx: <><h2 id="eq-misc-cipher_rings-cipher-rings">Cipher rings</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 203</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>This set of bulky wooden rings is the key to a substitution code set at the rings' creation. A base set comes with two identical rings. Additional rings can be made for 4 gp apiece. Using the cipher rings' code enables you to create or decode a written message (no check required). Deciphering the message without the correct ring requires a DC 25 Linguistics check.</p>
</>};
const _city_map = {title: "City map", jsx: <><h2 id="eq-misc-city_map-city-map">City map</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 12</Link><br/><strong>Price</strong> 40 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>This map aids in navigating a single city. You can consult the map for 1 minute to gain a +2 bonus when attempting a Knowledge (local) check to identify a location in that city (and can attempt checks for DCs above 10 even if untrained) or when attempting a DC 15 Survival check to avoid getting lost in that city.</p>
</>};
const _clatterstone = {title: "Clatterstone", jsx: <><h2 id="eq-misc-clatterstone-clatterstone">Clatterstone</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 30</Link><br/><strong>Price</strong> 30 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>Comprising several chunks of magnetized ore connected by twine, a clatterstone creates an intense racket when it strikes a solid surface. The combination of magnetic disturbances, noise, and vibrations interferes with <Link to="/umr/blindsight">blindsight</Link>. A creature using blindsight perceives a detonated clatterstone as a Medium target until it attempts to interact with the perceived "creature" or identifies it with some other sense, such as darkvision. You can throw a clatterstone as a ranged attack with a range increment of 20 feet, and it remains active for 1d4+1 rounds before becoming inert.</p>
</>};
const _clay_whippoorwill = {title: "Clay whippoorwill", jsx: <><h2 id="eq-misc-clay_whippoorwill-clay-whippoorwill">Clay whippoorwill</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 42</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>In addition to being an instrument suitable for Perform (wind) checks, this elaborately crafted whippoorwill-shaped clay ocarina also doubles the effective range of the secret whistled Nightsong language to a distance of 1,000 feet.</p>
</>};
const _clay = {title: "Clay", jsx: <><h2 id="eq-misc-clay-clay">Clay</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 1 sp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This pound of clay is sold in a watertight container to keep it soft, can be hardened by sunlight, baking, or any heat source.</p>
</>};
const _clear_ear = {title: "Clear ear", jsx: <><h2 id="eq-misc-clear_ear-clear-ear">Clear ear</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 15 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Black Market</p>
<p>This green gel is poured into the user's ear and takes effect 2 hours later, enhancing senses and memory but increasing irritability. For 6 hours, the user gains a +2 alchemical bonus on Perception and Knowledge checks and a -2 penalty on all Charisma-based checks.</p>
</>};
const _cleats = {title: "Cleats", jsx: <><h2 id="eq-misc-cleats-cleats">Cleats</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 89</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 185</Link>, <Link to="/source/pathfinder_51_the_hungry_storm">Pathfinder #51: The Hungry Storm pg. 67</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Clothing</p>
<p>Cleats reduce the penalty for walking over slick surfaces by 50%. For example, walking across ice normally costs 2 squares of movement (1 square plus a 1 square penalty) for every square of movement, but with cleats it costs only 1.5 squares for every square. Cleats cause damage to any type of finished flooring. They may supplement another outfit.</p>
</>};
const _clerics_kit = {title: "Cleric's kit", jsx: <><h2 id="eq-misc-clerics_kit-clerics-kit">Cleric's kit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 16 gp; <strong>Weight</strong> 32 lbs.<br/><strong>Category</strong> Kits</p>
<p>This includes a <Link to="/eq-misc/backpack">backpack</Link>, a <Link to="/eq-misc/bedroll">bedroll</Link>, a <Link to="/eq-misc/belt_pouch">belt pouch</Link>, <Link to="/eq-misc/candles">candles</Link> (10), a <Link to="/eq-misc/holy_text">cheap holy text</Link>, a <Link to="/eq-misc/flint_and_steel">flint and steel</Link>, an <Link to="/eq-misc/iron_pot">iron pot</Link>, a <Link to="/eq-misc/mess_kit">mess kit</Link>, <Link to="/eq-misc/rope">rope</Link>, <Link to="/eq-misc/soap">soap</Link>, a <Link to="/eq-misc/spell_component_pouch">spell component pouch</Link>, <Link to="/eq-misc/torches">torches</Link> (10), <Link to="/eq-misc/trail_rations">trail rations</Link> (5 days), a <Link to="/eq-misc/waterskin">waterskin</Link>, and a <Link to="/eq-misc/wooden_holy_symbol">wooden holy symbol</Link>.</p>
</>};
const _clerics_vestments = {title: "Cleric's vestments", jsx: <><h2 id="eq-misc-clerics_vestments-clerics-vestments">Cleric's vestments</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 89</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 159</Link><br/><strong>Price</strong> 5 gp; <strong>Weight</strong> 6 lbs.<br/><strong>Category</strong> Clothing</p>
<p>These ceremonial clothes are worn when performing priestly functions within a church or temple, and aren't well suited to adventuring. A cleric's vestments typically include a cassock, stole, and surplice. The colors usually correspond to the deity worshiped, and while some priests may choose elaborate embroidery with ecclesiastical themes, others find merit in humble simplicity.</p>
</>};
const _click_claw = {title: "Click-claw", jsx: <><h2 id="eq-misc-click_claw-click-claw">Click-claw</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_sea">Blood of the Sea pg. 18</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>This small metallic device resembles a crab's claw. When the item is pinched and released, friction on the claw's inner surface creates a loud clicking noise that carries up to a half mile underwater. The intensity of the sound decreases as the click passes through water, providing a listener familiar with the sound a general sense of the distance and direction of the noise's origin (Perception DC 0, +1 per 100 feet between the click-claw and the listener). Click-claws are particularly useful for keeping a group together in murky water, and many undersea animal handlers train their animals to respond to the noise.</p>
</>};
const _climbers_kit = {title: "Climber's kit", jsx: <><h2 id="eq-misc-climbers_kit-climbers-kit">Climber's kit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 77</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 80 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Tools</p>
<p>These crampons, pitons, ropes, and other tools give you a +2 circumstance bonus on Climb checks.</p>
</>};
const _climbers_plank = {title: "Climber's plank", jsx: <><h2 id="eq-misc-climbers_plank-climbers-plank">Climber's plank</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 12</Link><br/><strong>Price</strong> 20 gp; <strong>Weight</strong> 4 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>A climber's plank is a 1-foot-wide wooden plank with a steel-capped spike carved on one end. The spiked end can be driven into a wall to create a temporary platform. Driving a climber's plank into a wall is a standard action and requires a successful Strength check, with a DC equal to the break DC of the surface material. Removing an embedded climber's plank requires a second Strength check at the same DC. You can easily stand on a pair of climber's planks, but standing on a single plank requires a successful DC 5 Acrobatics check. Climber's planks are sold in pairs.</p>
</>};
const _clockwork_dial = {title: "Clockwork dial", jsx: <><h2 id="eq-misc-clockwork_dial-clockwork-dial">Clockwork dial</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 4</Link><br/><strong>Price</strong> 150 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This brass timepiece can be wound with a small key, causing it to count down until it reaches the end of its duration, at which point it emits a small chime. Most dials have a maximum duration of 60 minutes, with each turn of a key adding 10 minutes, though some are crafted with longer or shorter durations and intervals.</p>
</>};
const _clockwork_oar = {title: "Clockwork oar", jsx: <><h2 id="eq-misc-clockwork_oar-clockwork-oar">Clockwork oar</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 16</Link><br/><strong>Price</strong> 500 gp; <strong>Weight</strong> 50 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This clockwork device is powered by heatstones and seawater and can turn a ship's <Link to="/eq-misc/oar">oar</Link> with tireless mechanical strokes. When installed on a water vehicle that uses muscle as a means of propulsion, a clockwork oar performs the function of one Medium rower. A broken clockwork oar functions only half as well as an unbroken one, so two broken clockwork oars are required to perform the function of one Medium rower.</p>
<p>For <Link to="/rule/propulsion_and_driving_checks">driving checks</Link> with a water vehicle powered with only clockwork oars, the driver must attempt Disable Device or Knowledge (engineering) checks instead of the skill checks listed in the vehicle's driving check entry in its stat block. (These checks represent the sailor ensuring that all of the oars are moving in unison and without impediment.) If a water vehicle is powered with one or more clockwork oars but not solely with clockwork oars, the skills used for driving checks remain unchanged.</p>
</>};
const _clockwork_prowler_advanced = {title: "Clockwork prowler (advanced)", jsx: <><h2 id="eq-misc-clockwork_prowler_advanced-clockwork-prowler-advanced">Clockwork prowler (advanced)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 48</Link><br/><strong>Price</strong> 1,500 gp; <strong>Weight</strong> 30 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>A more advanced version of the <Link to="/eq-misc/clockwork_prowler">clockwork prowler</Link>, this device is more metal than wood. It moves at a speed of 20 feet and can be programmed with up to four right-angle turns. Each turn requires 1 round to program along with a DC 15 Disable Device check. If this check is failed, roll d% each time the prowler attempts to turn. On a result of 1-10, it fails to turn. On a result of 11-20, it instead turns on the next round. An advanced clockwork prowler can carry up to 60 pounds of weight at full speed, or up to 120 pounds at a speed of 10 feet. It has hardness 10, 150 hit points, and when in motion has AC 15 (a motionless advanced clockwork prowler has AC 8).</p>
</>};
const _clockwork_prowler = {title: "Clockwork prowler", jsx: <><h2 id="eq-misc-clockwork_prowler-clockwork-prowler">Clockwork prowler</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_field_guide">Pathfinder Society Field Guide pg. 48</Link><br/><strong>Price</strong> 500 gp; <strong>Weight</strong> 25 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This 2-foot-tall wooden clockwork automaton is shaped roughly like a short-backed, wheeled chair. When wound up with the folding handle at its side, the clockwork prowler trundles forward at a speed of 15 feet per round for up to 2 minutes. A clockwork prowler cannot move through <Link to="/rule/difficult_terrain">difficult terrain</Link>. Each round of vigorous winding powers 2 rounds of movement. If its brake is not released immediately after winding, the prowler loses 1 round of movement for every 2 rounds it sits idle. The clockwork prowler can carry up to 20 pounds of weight at full speed, or up to 50 pounds at a speed of 10 feet. Higher weights prevent the prowler from moving. A clockwork prowler has hardness 5 and 90 hit points, and when in motion has AC 12 (a motionless clockwork prowler has AC 5).</p>
</>};
const _cloud_puff = {title: "Cloud Puff", jsx: <><h2 id="eq-misc-cloud_puff-cloud-puff">Cloud Puff</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 153</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> -<br/><strong>Category</strong> <Link to="/rule/herbalism">Herbs</Link><br/><strong>Gather</strong> DC 18; <strong>Yield</strong> 1 dose<br/><strong>Terrain</strong> any mountains<br/><strong>Preparation</strong> After soaking in salt water for 1 hour, a cloud puff must be dried in a delicate process that requires it to be turned three times per hour for 4 hours. This requires a successful DC 12 Craft (alchemy) check.<br/><strong>Use</strong> By crushing a dried cloud puff and inhaling the spores, a creature becomes light-headed and its mind grows resistant to outside influences. For the next hour, the creature gains a +2 alchemical bonus on saving throws against mind-affecting effects but takes a -2 penalty on Wisdom-based skill checks.</p>
<p>The spores of this odorous pale-gray fungus cause a euphoric light-headedness.</p>
</>};
const _coach_cab_travel_per_mile = {title: "Coach cab (travel, per mile)", jsx: <><h2 id="eq-misc-coach_cab_travel_per_mile-coach-cab">Coach cab</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 159</Link><br/><strong>Price</strong> -; <strong>Price of Passage</strong> (per mile) 3 cp<br/><strong>Category</strong> Transport, Land</p>
<p>The price given is for a ride in a coach that transports people (and light cargo) between towns. For a ride in a cab that transports passengers within a city, 1 copper piece usually takes you anywhere you need to go.</p>
</>};
const _cobbled_item = {title: "Cobbled item", jsx: <><h2 id="eq-misc-cobbled_item-cobbled-item">Cobbled item</h2>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion pg. 12</Link><br/><strong>Price</strong> Special; <strong>Weight</strong> Special<br/><strong>Category</strong> Adventuring Gear</p>
<p>Goblins are masters at crafting things from bits of rubbish. The category of "cobbled item" is a general catch-all to describe any piece of equipment that has been repaired or modified by goblins. Such items are of an inferior quality - whenever they're used as part of a skill check or attack roll, they have a 10% chance of being broken. Cobbled items can never be masterwork items. A cobbled item is of lesser quality than a normal item, and thus costs only 75% as much as the normal item, but is often much bulkier. Any cobbled item of 1 pound or more in weight actually weighs twice as much as a normal item of its type. Any item that normally costs more than 50 gp can never be a cobbled item, nor can alchemical items be cobbled. At the GM's discretion, other items may not be able to be cobbled items either.</p>
</>};
const _code_rod = {title: "Code rod", jsx: <><h2 id="eq-misc-code_rod-code-rod">Code rod</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 232</Link><br/><strong>Price</strong> 1 sp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>To all appearances, this device is nothing more than a plain rod, such as a dowel, although it can be made in the form of any cylindrical object, such as a <Link to="/eq-misc/cane">cane</Link> or walking stick, curtain rod, <Link to="/eq-misc/scroll_case">scroll case</Link>, <Link to="/eq-misc/wind_chime">wind chime</Link>, or <Link to="/eq-weapon/blowgun">blowgun</Link>. The simplest form of code rod costs 1 sp and weighs 1 pound. If the rod has another use other than as a code rod, it uses the higher price and weight of the two items. Two code rods of matching circumference must be used in pairs to work properly. The second rod can be an item similar to the first, or it can simply be made to the same dimensions. To use a code rod, a long, narrow strip of paper is wrapped around the rod in a spiral pattern such that the edge of the paper touches the previous circuit with each pass, forming a continuous surface. A message is written along the length of the rod, one character to each coil of paper, row by row, until the paper is full. Once the message is completed, the strip of paper is unwound, rendering the message indecipherable. It can then be rolled up and sent to the recipient, who wraps it around the other rod and can then read the message. The users can write in plain language or further encode the message. Someone intercepting the message, if they recognize the use of a code rod, can attempt to find another rod of similar circumference, using Linguistics to crack the code rod's message.</p>
</>};
const _coffee_cup = {title: "Coffee (cup)", jsx: <><h2 id="eq-misc-coffee_cup-coffee-cup">Coffee (cup)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 95</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 1 cp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Food/Drink</p>
<p>This drink is brewed by pouring boiling water through crushed, roasted coffee beans. Two cups is potent enough to reduce the penalties from the <Link to="/misc/fatigued">fatigued</Link> condition from -2 to -1 for 1 hour.</p>
<p>Brewing your own coffee requires ground coffee beans (5 cp for 1 pound of coffee beans, or 8 cp for 1 pound of ground beans) and a cooking device. You can boil the grounds in a pot, then pour the liquid after allowing the solids to settle, or filter the drink by pouring it through a sieve or cloth. Many travelers prefer the convenience of using a <Link to="/eq-misc/coffee_pot">coffee pot</Link>.</p>
</>};
const _coffee_pot = {title: "Coffee pot", jsx: <><h2 id="eq-misc-coffee_pot-coffee-pot">Coffee pot</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 3 gp; <strong>Weight</strong> 4 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This tall, teapot-like device contains a small chamber for coffee grounds and a large chamber for water, connected by a small tube. Heating the pot forces boiling water through the tube and into the grounds. A glass knob at the top of the tube allows you to see the color of the brew and stop when it is sufficiently strong. It can brew up to 4 <Link to="/eq-misc/coffee_cup">cups of coffee</Link> at a time. It can also be used to make tea, steep medicinal herbs, or just boil water.</p>
</>};
const _coffin_common = {title: "Coffin (common)", jsx: <><h2 id="eq-misc-coffin_common-coffin">Coffin</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link>, <Link to="/source/pathfinder_campaign_setting">Pathfinder Campaign Setting pg. 213</Link><br/><strong>Price</strong> 10 gp (common), 100 gp (ornate); <strong>Weight</strong> 30 lbs. (common), 50 lbs. (ornate)</p>
<p>A plain coffin is made of simple wood and has a loose, flat lid that can be nailed onto it. Ornate coffins are favored by aristocratic families for displaying their dead, and include upholstered cloth liners and a hinged lid.</p>
</>};
const _cold_weather_outfit = {title: "Cold-weather outfit", jsx: <><h2 id="eq-misc-cold_weather_outfit-cold-weather-outfit">Cold-weather outfit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 89</Link>, <Link to="/source/pathfinder_51_the_hungry_storm">Pathfinder #51: The Hungry Storm pg. 67</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 159</Link><br/><strong>Price</strong> 8 gp; <strong>Weight</strong> 7 lbs.<br/><strong>Category</strong> Clothing</p>
<p>This outfit is designed for mountaineering or hunting and traveling in icy climates. It includes a coat of wool or thick animal fur, a linen shirt, a wool cap, a heavy cloak, a heavy skirt or pants, and waterproof leather boots. In some regions, the outfit may be composed primarily of fur and animal pelts. This outfit grants a +5 circumstance bonus on Fortitude saving throws against exposure to <Link to="/rule/cold">cold weather</Link>.</p>
<p><strong>Tear-away clothing</strong><br/><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 89</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> +5 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Clothing</p>
<p>Sneaks and thieves know the value of a good disguise. The ability to remove that disguise in a hurry, thus revealing the next layer of disguise, is nearly as valuable. Tear-away clothing is generally loose fitting and allows another layer of clothing to be worn underneath. The seams on this clothing are designed to break easily, making it a simple matter (a standard action) to remove these items and walk away with none the wiser. Any outfit can be crafted as tear-away clothing for an additional price.</p>
</>};
const _collapsible_bathtub = {title: "Collapsible bathtub", jsx: <><h2 id="eq-misc-collapsible_bathtub-collapsible-bathtub">Collapsible bathtub</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 15 gp; <strong>Weight</strong> 20 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>After 10 minutes of assembly, this collection of wooden slats provides support for a cylindrical watertight canvas cloth. It can hold enough water to allow 1 Medium creature to bathe in comfort without any of the risks that might come from entering lakes, rivers, or other bodies of water.</p>
</>};
const _collapsible_plank = {title: "Collapsible plank", jsx: <><h2 id="eq-misc-collapsible_plank-collapsible-plank">Collapsible plank</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 4 sp; <strong>Weight</strong> 10 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>Hinged in two places, collapsible planks can hold 250 pounds before breaking. The 10-foot-long plank folds down into a 3-foot-by-1-foot-by-6-inch bundle. Folding or unfolding it is a standard action.</p>
</>};
const _collapsible_rowboat = {title: "Collapsible rowboat", jsx: <><h2 id="eq-misc-collapsible_rowboat-collapsible-rowboat">Collapsible rowboat</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 19</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> 40 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This boat has a canvas hull and wooden frame that can be easily disassembled. When collapsed, the boat fits into a pack that can be carried by one person. When expanded, this boat has the same base statistics as a <Link to="/eq-misc/rowboat">rowboat</Link>. Expanding or collapsing it takes 5 minutes.</p>
</>};
const _collapsible_trampoline = {title: "Collapsible trampoline", jsx: <><h2 id="eq-misc-collapsible_trampoline-collapsible-trampoline">Collapsible trampoline</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 203</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 10 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This compact trampoline comes apart and rolls up like a tent for easy transport. Setting up or taking apart the trampoline takes 1 minute. When operated by two creatures, the collapsible trampoline confers a +5 bonus on all Acrobatics checks made to jump. If a falling creature lands on the trampoline, it ignores the first 10 feet of falling damage.</p>
</>};
const _combat_scabbard = {title: "Combat scabbard", jsx: <><h2 id="eq-misc-combat_scabbard-combat-scabbard">Combat scabbard</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 1 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This scabbard is an <Link to="/misc/improvised_weapon">improvised weapon</Link> designed to allow you to remove it from your belt as a swift action when drawing the weapon it contains. Taking the <Link to="/feat/equipment_trick">Equipment Trick</Link> feat for a scabbard gives you additional combat options for using a scabbard. For the purpose of fighter <Link to="/ability/weapon_groups">weapon groups</Link>, a scabbard for a heavy blade is considered a hammer, and a scabbard for a light blade is considered a close weapon.</p>
</>};
const _commissioned_broadsheet_setup_and_proof_print = {title: "Commissioned broadsheet (setup and proof print)", jsx: <><h2 id="eq-misc-commissioned_broadsheet_setup_and_proof_print-commissioned-broadsheet">Commissioned broadsheet</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 5</Link><br/><strong>Price</strong> 150 gp (print run (500 broadsheets)), 50 gp (setup and proof print); <strong>Weight</strong> - (print run (500 broadsheets)), - (setup and proof print)</p>
<p>It takes 2 to 4 weeks for printers reproducing large images or those who have only engraved-plate printing presses to prepare the plate for a commissioned <Link to="/eq-misc/broadsheet">broadsheet</Link>. Printers with movable-type printing presses can prepare a text-only broadsheet in as little as 4 hours. Once the setup is complete (which includes a proof print), the printer can produce up to 500 copies of the broadsheet daily (about 60 per hour). A commissioned broadsheet can be used to spread a rumor requiring the author to attempt any necessary skill checks. The author takes a -8 penalty on these checks because the broadsheet cannot provide vocal or nonverbal cues, but if he's successful, spreading the rumor takes only 1d4 days (or 1 day, if smaller than a small town). If the broadsheets are delivered by trained criers or others attempting to spread the rumor, use the propaganda check result of either the author or the crier (whichever is higher) with a +2 bonus.</p>
</>};
const _compact_spellbook = {title: "Compact spellbook", jsx: <><h2 id="eq-misc-compact_spellbook-compact-spellbook">Compact spellbook</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 27</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Tools</p>
<p>The need to be able to record and travel with dozens or even hundreds of spells often forces elven wizards to seek lighter spellbooks. Compact spellbooks hold only 70 pages of spells, but they weigh significantly less than an ordinary <Link to="/eq-misc/spellbook">spellbook</Link>.</p>
</>};
const _companion_cold_weather_outfit = {title: "Companion cold-weather outfit", jsx: <><h2 id="eq-misc-companion_cold_weather_outfit-companion-cold-weather-outfit">Companion cold-weather outfit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 242</Link><br/><strong>Price</strong> 15 gp; <strong>Weight</strong> 6 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This vestment works just like a <Link to="/eq-misc/cold_weather_outfit">cold-weather outfit</Link>, granting a +5 circumstance bonus on Fortitude saving throws against exposure to cold weather, except it is custom made for an <Link to="/sidekick/animal_companion">animal companion</Link>. The added cost represents custom tailoring to ensure that the furs used don't cause unwanted reactions from the animal wearing the outfit.</p>
</>};
const _companion = {title: "Companion", jsx: <><h2 id="eq-misc-companion-companion">Companion</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 99</Link><br/><strong>Price</strong> 5 cp-10 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Lodging/Services</p>
<p>Whether a brazen strumpet, gigolo, saucy tart, escort, or expensive doxy, this person is available for an adventurer who needs intimacy. An hour's diversion typically costs a few silver pieces plus the price of a room.</p>
</>};
const _compass = {title: "Compass", jsx: <><h2 id="eq-misc-compass-compass">Compass</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 184</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>An ordinary compass that points to the magnetic north pole grants you a +2 circumstance bonus on Survival checks made to avoid becoming lost. You can also use it to grant the same bonus on Knowledge (dungeoneering) checks made to navigate underground.</p>
</>};
const _compressed_air = {title: "Compressed air", jsx: <><h2 id="eq-misc-compressed_air-compressed-air">Compressed air</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars pg. 19</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 10 lbs.<br/><strong>Category</strong> Tools</p>
<p>Longer lasting than an air bladder, a jar of compressed air comes with a breathing apparatus that can be strapped over the mouth with a leather cord and provides enough air for a Medium character to breathe normally for 10 minutes (20 minutes for a Small character).</p>
</>};
const _concealable_thieves_tools = {title: "Concealable thieves' tools", jsx: <><h2 id="eq-misc-concealable_thieves_tools-concealable-thieves-tools">Concealable thieves' tools</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 233</Link><br/><strong>Price</strong> 190 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>Smaller and made of stronger materials than most thieves' tools, the items in this kit are much easier to conceal. You gain a +4 bonus on Sleight of Hand skill checks to conceal these tools on your body. They otherwise function as <Link to="/eq-misc/masterwork_thieves_tools">masterwork thieves tools</Link> (granting a +2 circumstance bonus on Disable Device checks).</p>
</>};
const _concealment_coin = {title: "Concealment coin", jsx: <><h2 id="eq-misc-concealment_coin-concealment-coin">Concealment coin</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 233</Link><br/><strong>Price</strong> 12 gp; <strong>Weight</strong> 1/10 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>A concealment coin appears in all respects like a typical coin of the realm and is often crafted from an ordinary coin - though for soft metals like gold, the coin is typically made with an iron or steel interior and then plated with the more valuable metal. Twisting the coin along its edge unscrews the two halves, revealing a thin, hollow space inside. Such coins are often used to hide small messages written on very fine paper for covert delivery. Noticing a concealment coin's true nature requires a successful DC 25 Perception check.</p>
</>};
const _contracting_rope = {title: "Contracting rope", jsx: <><h2 id="eq-misc-contracting_rope-contracting-rope">Contracting rope</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 20</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This 50-foot length of <Link to="/eq-misc/silk_rope">silk rope</Link> is treated with alchemical reagents that give it a distinctly dusty odor. When any part of the rope is touched to an open flame, it suddenly contracts to one-fifth its original length, pulling any creature or object attached to one side to within 10 feet of the other; if multiple creatures are moved into the same square, they fall <Link to="/rule/prone">prone</Link> in randomly determined adjacent squares. Because of the sudden jerk, a creature holding a contracting rope must succeed at a DC 10 Climb check to avoid dropping it as it contracts (unless it is knotted around the creature's waist, clamped in a <Link to="/eq-armorenh/locked_gauntlet">locked gauntlet</Link>, or otherwise firmly attached to the creature). The rope fails to contract if it would pull more than 1,000 pounds horizontally or lift more than 250 pounds vertically. Once activated, the rope slowly unravels to its normal length over the course of 24 hours and can't be activated again until such time has passed.</p>
</>};
const _conversation_tube = {title: "Conversation tube", jsx: <><h2 id="eq-misc-conversation_tube-conversation-tube">Conversation tube</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 12</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> 3 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>Used to carry out a private conversation even in a crowded room or public place, this 5-foot-long, 1/2-inch-wide leather hose widens into a copper bell at each end. To use it, one conversation partner holds her end to her ear while her partner speaks into his end, switching their postures for each reply. Conversing through a conversation tube increases the DC of Perception checks to eavesdrop on the conversation by +5 and negates the risk of lipreading but takes twice as long as conversing normally.</p>
</>};
const _convocation_bells = {title: "Convocation bells", jsx: <><h2 id="eq-misc-convocation_bells-convocation-bells">Convocation bells</h2>
<p><strong>Sources</strong> <Link to="/source/disciples_doctrine">Disciple's Doctrine pg. 28</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> 10 lbs.<br/><strong>Category</strong> Tools</p>
<p>This set of simple brass bells is held in a wheeled stand that allows bell ringers to easily move the ensemble. The bells are carefully constructed and ordered to enable ringers to perform the melodies of songs or hymns of a particular religion.</p>
</>};
const _cooking_kit = {title: "Cooking kit", jsx: <><h2 id="eq-misc-cooking_kit-cooking-kit">Cooking kit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 3 gp; <strong>Weight</strong> 16 lbs.<br/><strong>Category</strong> Kits</p>
<p>This kit contains an <Link to="/eq-misc/iron_pot">iron pot</Link>, an iron <Link to="/eq-misc/skillet">skillet</Link>, a ladle, a skewer, a wooden cutting board, a cutting knife, an iron tripod for the pot, a packet of tinder, and a small selection of local or otherwise easy to find seasonings. You can attach the skewer to the tripod for roasting small game animals. All the component pieces (except the skillet) fit within the pot for easy storage and transport.</p>
</>};
const _cooking_powder = {title: "Cooking powder", jsx: <><h2 id="eq-misc-cooking_powder-cooking-powder">Cooking powder</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 44</Link>, <Link to="/source/pathfinder_106_for_queen_and_empire">Pathfinder #106: For Queen and Empire pg. 75</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>By boiling certain seeds with handfuls of rust, <Link to="/race/halfling">halfling</Link> <Link to="/class/alchemist">alchemists</Link> create these red flakes, which smolder slowly when touched by a spark or flame. If sprinkled over food and lit, a handful of cooking powder can cook meat or vegetables in 20 minutes without light or significant heat, though it lends a metallic flavor to any foods. If held to a living creature's flesh, smoldering cooking powder deals 1 point of fire damage per minute for 20 minutes. One jar of cooking powder is enough to cook up to 5 pounds of food in 1-pound increments. Crafting a jar of cooking powder requires a successful DC 15 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 15</p>
</>};
const _cooler_chest = {title: "Cooler chest", jsx: <><h2 id="eq-misc-cooler_chest-cooler-chest">Cooler chest</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 243</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> 60 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This chest can contain up to 4 cubic feet of goods, and it has a lining of insulating material between two sheets of wood. As long as the chest is partially filled with a cold substance - such as cold water or ice - items stored within decompose at half their regular rate. Ice melts on a consistent basis (typically four to six times in a 24-hour period) and must be regularly replenished to maintain the effectiveness of this chest.</p>
</>};
const _copy_of_a_key = {title: "Copy of a key", jsx: <><h2 id="eq-misc-copy_of_a_key-copy-of-a-key">Copy of a key</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Adventuring Gear</p>
<p>An artisan can make a working copy of a key in an hour (making a duplicate that looks exactly like the original requires a skilled smith, a DC 25 Craft check, and 1 day).</p>
</>};
const _coral_boulder = {title: "Coral boulder", jsx: <><h2 id="eq-misc-coral_boulder-coral-boulder">Coral boulder</h2>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook pg. 26</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Tools</p>
<p>This sponge-sized brick is actually a desiccated chunk of living coral. When exposed to at least 1 gallon of water, it expands into a full-sized boulder within 1 minute. A fully expanded coral boulder is an irregular sphere 3 feet in diameter. An expanded boulder has a hardness of 7, has 55 hit points, and weighs 8 pounds. The water in a coral boulder slowly evaporates if it's left in a dry environment, and the boulder shrinks back to its original size in about a week. If dropped in water, a coral boulder sinks straight down, and is not moved by tides or flowing water.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _corentyn_wine_bottle = {title: "Corentyn wine (bottle)", jsx: <><h2 id="eq-misc-corentyn_wine_bottle-corentyn-wine">Corentyn wine</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> 15 gp/bottle; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Food/Drink</p>
<p>Red and white wines grown in the salt spray of Corentyn have a sweet-tart flavor valued by nobles throughout Cheliax.</p>
</>};
const _cork_vest = {title: "Cork vest", jsx: <><h2 id="eq-misc-cork_vest-cork-vest">Cork vest</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 203</Link><br/><strong>Price</strong> 25 gp; <strong>Weight</strong> 1 lb.<br/><strong>Category</strong> Clothing</p>
<p>This fabric vest contains pockets full of cork, providing the wearer additional buoyancy. Originally worn by fishers and sailors, it protects against drowning. While wearing a cork vest, you take a -2 penalty on Dexterity and Swim checks, but instead of going underwater after failing the check by 5 or more, you go underwater only if you fail by 10 or more. Additionally, you gain a +4 bonus on Swim checks to avoid damage from fatigue. The cork vest can be worn under armor.</p>
</>};
const _corset = {title: "Corset", jsx: <><h2 id="eq-misc-corset-corset">Corset</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 20</Link><br/><strong>Price</strong> 1 sp-200 gp; <strong>Weight</strong> 3 lbs.<br/><strong>Category</strong> Clothing</p>
<p>Sewn-in boning and laces allow this bodice to adjust your waist size in a way considered alluring by some cultures. The restrictive nature of this garment makes it a poor choice for combat or other athletic exertions, but you can easily conceal a thin knife in the corset's boning. The price varies greatly depending on the corset's quality; the cheapest corsets are made of simple cloth and cost mere silver pieces, while the most expensive feature silk brocade and are decorated with pearls or other costly adornments.</p>
</>};
const _cosmogram = {title: "Cosmogram", jsx: <><h2 id="eq-misc-cosmogram-cosmogram">Cosmogram</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars pg. 26</Link><br/><strong>Price</strong> 200 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Tools</p>
<p>This eldritch chart describes part of the unfathomably vast shape of the physical universe and the subtler motions of the stars. A cosmogram grants a +1 circumstance bonus on Knowledge (geography) checks relating to stars and on Survival checks to navigate the void of space between star systems. A cosmogram can be consulted while using an <Link to="/eq-misc/orrery">orrery</Link> as a focus for <Link to="/spell/augury">augury</Link>. Doing so increases the chance of a successful reading by 2%.</p>
</>};
const _cot = {title: "Cot", jsx: <><h2 id="eq-misc-cot-cot">Cot</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 1 gp; <strong>Weight</strong> 30 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This elevated camp bed is made of wood and canvas, and is particularly useful when the ground is wet or rocky. It is large enough for a full-grown human, but folds down into a 4-foot by 9-inch cylindrical bag.</p>
</>};
const _courtesans_kit = {title: "Courtesan's kit", jsx: <><h2 id="eq-misc-courtesans_kit-courtesans-kit">Courtesan's kit</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 204</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Kits</p>
<p>This kit contains items to assist a courtesan in soothing the body and mind. For the body, the kit contains a razor, scented oils and salves, fragrances, a warming pot, and a variety of appealing outfits. Books of poetry, literature, and plays - often focusing on salacious topics and full of double entendres - entertain the mind.</p>
</>};
const _courtesans_outfit = {title: "Courtesan's outfit", jsx: <><h2 id="eq-misc-courtesans_outfit-courtesans-outfit">Courtesan's outfit</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 20</Link><br/><strong>Price</strong> 8 gp; <strong>Weight</strong> 4 lbs.<br/><strong>Category</strong> Clothing</p>
<p>This outfit includes fine silk or satin garments tailored to complement your figure. In addition, the outfit contains a loose shawl or robe with several discreet pockets for items such as perfume, massage oils, or even a small dagger.</p>
<p><strong>Tear-away clothing</strong><br/><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 89</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> +5 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Clothing</p>
<p>Sneaks and thieves know the value of a good disguise. The ability to remove that disguise in a hurry, thus revealing the next layer of disguise, is nearly as valuable. Tear-away clothing is generally loose fitting and allows another layer of clothing to be worn underneath. The seams on this clothing are designed to break easily, making it a simple matter (a standard action) to remove these items and walk away with none the wiser. Any outfit can be crafted as tear-away clothing for an additional price.</p>
</>};
const _courtiers_outfit = {title: "Courtier's outfit", jsx: <><h2 id="eq-misc-courtiers_outfit-courtiers-outfit">Courtier's outfit</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 89</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 159</Link><br/><strong>Price</strong> 30 gp; <strong>Weight</strong> 6 lbs.<br/><strong>Category</strong> Clothing</p>
<p>This outfit includes tailored clothes in whatever fashion happens to be current in noble courts of that region. Anyone trying to influence nobles or courtiers while wearing street dress will have a hard time of it (-2 penalty on Charisma-based skill checks to influence such individuals). If you wear this outfit without jewelry (costing an additional 50 gp), you look like an out-of-place commoner.</p>
<p><strong>Tear-away clothing</strong><br/><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 89</Link>, <Link to="/source/adventurers_armory">Adventurer's Armory pg. 19</Link><br/><strong>Price</strong> +5 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Clothing</p>
<p>Sneaks and thieves know the value of a good disguise. The ability to remove that disguise in a hurry, thus revealing the next layer of disguise, is nearly as valuable. Tear-away clothing is generally loose fitting and allows another layer of clothing to be worn underneath. The seams on this clothing are designed to break easily, making it a simple matter (a standard action) to remove these items and walk away with none the wiser. Any outfit can be crafted as tear-away clothing for an additional price.</p>
</>};
const _covenant_rings = {title: "Covenant rings", jsx: <><h2 id="eq-misc-covenant_rings-covenant-rings">Covenant rings</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 21</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Clothing</p>
<p>These silver rings are always sold in uniquely crafted pairs - usually one made in a Varisian style and one in an old Korvosan style. Originally made to celebrate the uniting of the Korvosan dissidents and Varisian locals at the city's outset, they are now commonly sought by young lovers, very close friends, and other intimate pairs. When two emotionally intimate creatures each wear one of the rings in a set, both wearers gain a +1 bonus on saving throws against fear effects. This bonus ends if the creatures' emotional bond is severed (at the GM's discretion), one of the creatures removes a ring and returns it to the other creature, or a bonded creature is no longer wearing the ring (or is no longer alive or on the same plane).</p>
</>};
const _crab = {title: "Crab", jsx: <><h2 id="eq-misc-crab-crab">Crab</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 80</Link><br/><strong>Price</strong> 20 gp; <strong>Weight</strong> 5-7 lbs.<br/><strong>Category</strong> Mounts/Pets</p>
<p>Aquatic spellcasters often find large ocean crabs to be agreeable familiars. Without the bond of a familiar, however, these crustacean's lack of intelligence makes them dull pets.</p>
</>};
const _croquet_set = {title: "Croquet set", jsx: <><h2 id="eq-misc-croquet_set-croquet-set">Croquet set</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 92</Link><br/><strong>Price</strong> 5 sp; <strong>Weight</strong> 10 lbs.<br/><strong>Category</strong> Entertainment</p>
<p>This set includes four wooden mallets, nine wooden wickets (goals), and four wooden balls.</p>
</>};
const _crossword = {title: "Crossword", jsx: <><h2 id="eq-misc-crossword-crossword">Crossword</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 92</Link><br/><strong>Price</strong> 1 cp-1 sp; <strong>Weight</strong> -<br/><strong>Category</strong> Entertainment</p>
<p>These word puzzles can be found in many languages. A typical one is drawn on leather or wood in a 15-by-15 square grid. Larger grids allow longer words and tend to be more difficult.</p>
</>};
const _crowbar = {title: "Crowbar", jsx: <><h2 id="eq-misc-crowbar-crowbar">Crowbar</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link>, <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 158</Link><br/><strong>Price</strong> 2 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>This versatile tool is designed to help pry open whatever the user desires. A crowbar grants a +2 circumstance bonus on Strength checks made to force open a door or chest. If it is used in combat, treat a crowbar as a one-handed <Link to="/misc/improvised_weapon">improvised weapon</Link> that deals bludgeoning damage equal to that of a <Link to="/eq-weapon/club">club</Link> of its size.</p>
</>};
const _crucible = {title: "Crucible", jsx: <><h2 id="eq-misc-crucible-crucible">Crucible</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 5</Link><br/><strong>Price</strong> 20 gp; <strong>Weight</strong> 30 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>A crucible is a type of vessel that can be heated to extreme temperatures for the purpose of inducing special alchemical reactions. A portable crucible is a cylinder 12 inches tall and 18 inches in diameter that weighs 3 pounds; it has the same price as a full-sized crucible. Use of a crucible requires a heat source.</p>
</>};
const _crusaders_cross_standard = {title: "Crusader's cross (standard)", jsx: <><h2 id="eq-misc-crusaders_cross_standard-crusaders-cross-standard">Crusader's cross (standard)</h2>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook pg. 18</Link><br/><strong>Price</strong> PFS Legal 50 gp (masterwork), PFS Legal 1 gp (standard); <strong>Weight</strong> - (masterwork), - (standard)</p>
<p>This palm-sized cross has arms of equal length and an emblem etched at the center. When purchased, the bearer's personal emblem or motto is etched on one side, and name, rank, and nation on the other. Common crusader's crosses are typically made of wood, while masterwork crosses - usually reserved for nobles, officers, or gifts to the families of fallen heroes - might be made of silver.</p>
</>};
const _crutch = {title: "Crutch", jsx: <><h2 id="eq-misc-crutch-crutch">Crutch</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 12</Link><br/><strong>Price</strong> 5 sp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>A crutch is a simple device composed of wood or metal and held under the arm to assist the injured or impaired with walking. Using a crutch requires a free hand, but does not impede movement speed for an experienced user. A Medium crutch can be wielded as a simple one-handed melee weapon that deals 1d4 points of bludgeoning damage.</p>
</>};
const _cryptography_book = {title: "Cryptography book", jsx: <><h2 id="eq-misc-cryptography_book-cryptography-book">Cryptography book</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 12</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>You can consult this book while attempting a Linguistics check to understand or create a coded message; doing so makes the task take 10 times longer than normal but grants you a +2 circumstance bonus on your check. The DC to decipher a message encoded with a cypher you invent is equal to the result of the Linguistics check you roll when creating the cypher. You can instead use one of the dozen example cyphers in the book, in which case the DC to understand the message without the cypher is 25, and any characters attempting to decipher the message do so automatically if they consult a copy of the same book.</p>
</>};
const _crystal_sweet_concoction = {title: "Crystal-sweet concoction", jsx: <><h2 id="eq-misc-crystal_sweet_concoction-crystal-sweet-concoction">Crystal-sweet concoction</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 25</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Concoctions</p>
<p>This sugary blue drink, often cut with mint to reduce the cloying sweetness, brightens your demeanor and sweetens your voice, granting a +2 alchemical bonus on Diplomacy checks. It renders you naive and perilously trusting, however, imparting a -4 penalty on your Sense Motive checks.</p>
</>};
const _curative_myrrh = {title: "Curative myrrh", jsx: <><h2 id="eq-misc-curative_myrrh-curative-myrrh">Curative myrrh</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 29</Link>, <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East pg. 19</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Remedies</p>
<p>When you burn this powerful resin, it fills eight contiguous 10-foot cubes with faint smoke that persists for 8 hours. Creatures resting or receiving long-term care in the smoke from curative myrrh regain 1 additional hit point per level. Multiple uses of curative myrrh in a 24-hour period do not stack.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 20</p>
</>};
const _cushion_inserts = {title: "Cushion inserts", jsx: <><h2 id="eq-misc-cushion_inserts-cushion-inserts">Cushion inserts</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 243</Link><br/><strong>Price</strong> 5 sp; <strong>Weight</strong> -<br/><strong>Category</strong> Clothing</p>
<p>These rubber boot or shoe inserts cushion your feet and improve your gait, granting you a +1 circumstance bonus on Constitution checks to continue running and to avoid nonlethal damage from a forced march.</p>
</>};
const _cypher_books = {title: "Cypher books", jsx: <><h2 id="eq-misc-cypher_books-cypher-books">Cypher books</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 56</Link><br/><strong>Price</strong> 150 gp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Adventuring Gear</p>
<p>These books, always sold in identical pairs, contain numbered grids on each page which simply and easily catalog random lists of words. This allows a user to write messages which substitute letters and numbers that reference the page, row, and column of a particular word found within the cypher book. A creature without access to the appropriate cypher book takes a -10 penalty on Linguistic checks made to decipher each page of a coded message. Writing a message using the cipher takes 10 times as long as writing an uncoded message, and decoding it with the cipher book takes as much time as writing the original coded message.</p>
</>};
const _dahaks_fire = {title: "Dahak's fire", jsx: <><h2 id="eq-misc-dahaks_fire-dahaks-fire">Dahak's fire</h2>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook pg. 18</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Dragoncraft</p>
<p>Made with dragon's gall, which is harvested from a recently deceased dragon's liver, Dahak's fire is a volatile alchemical reagent. Though inherently inert, the substance ignites when it comes into contact with fast-moving air, which makes it ideal for application to blades or arrows. When applied to a weapon or piece of ammunition as a standard action, the weapon deals an extra 2d6 points of fire damage on the next successful hit.</p>
<p>The <Link to="/feat/dragoncrafting">Dragoncrafting</Link> feat and a successful DC 20 Craft (alchemy) check are required to convert 1 vial of dragon's gall into 1 application of Dahak's fire.</p>
</>};
const _dampening_ointment = {title: "Dampening Ointment", jsx: <><h2 id="eq-misc-dampening_ointment-dampening-ointment">Dampening Ointment</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_139_the_dead_road">Pathfinder #139: The Dead Road pg. 63</Link><br/><strong>Price</strong> 250 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This pale salve is always cool to the touch, regardless of the surrounding temperature. When spread on your skin, it subtly alters your aura, making you more difficult for some creatures to detect. For 1 hour after applying the ointment to your skin, you can attempt a Stealth check to hide from any creature attempting to perceive you using <Link to="/umr/lifesense">lifesense</Link> or spiritsense (see the <Link to="/subtype/psychopomp">psychopomp</Link> subtype), even if you are clearly in that creature's perceptual field. Crafting this item requires a successful DC 25 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 25</p>
</>};
const _dancers_garb = {title: "Dancer's garb", jsx: <><h2 id="eq-misc-dancers_garb-dancers-garb">Dancer's garb</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 29</Link><br/><strong>Price</strong> 100 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Clothing</p>
<p>This combination of loose-fitting sashes, veils, and ornamentation accentuates a dancer's form and movements. Dancer's garb provides a +2 circumstance bonus on Perform (dance) checks, similar to that provided by masterwork instruments for other Perform skills, but does not grant this benefit when worn with armor or other concealing clothing.</p>
</>};
const _dancers_garb_silver = {title: "Dancer's garb, silver", jsx: <><h2 id="eq-misc-dancers_garb_silver-dancers-garb-silver">Dancer's garb, silver</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 29</Link><br/><strong>Price</strong> 200 gp; <strong>Weight</strong> 5 lbs.<br/><strong>Category</strong> Clothing</p>
<p>In addition to granting the same bonus on Perform (dance) checks as regular dancer's garb, silver dancer's garb is considered a silver instrument for <Link to="/arc-bard/silver_balladeer">silver balladeer</Link> bards. Silver dancer's garb can be made of <Link to="/eq-material/sunsilver">sunsilver</Link>; sunsilver dancer's garb costs an additional 3,000 gp and grants the same benefits as armor made of sunsilver. As with the bonus on Perform (dance) checks, this benefit functions only when no other armor or concealing clothing is worn.</p>
</>};
const _dandy_brush = {title: "Dandy brush", jsx: <><h2 id="eq-misc-dandy_brush-dandy-brush">Dandy brush</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 12</Link><br/><strong>Price</strong> 2 sp; <strong>Weight</strong> 2 lbs.<br/><strong>Category</strong> Animal Gear</p>
<p>This hard-bristled tool has a handle that slips over the wearer's hand, and is used by animal breeders, owners, and grooms to brush the animals in their care, loosening dirt and detritus from the creatures' coats and stimulating the skin so it produces the natural oils that keep them healthy and clean.</p>
</>};
const _daring_bravo_package = {title: "Daring bravo package", jsx: <><h2 id="eq-misc-daring_bravo_package-daring-bravo-package">Daring bravo package</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 4</Link><br/><strong>Price</strong> 1000 gp; <strong>Weight</strong> 76 1/2 lbs.<br/><strong>Category</strong> Kits</p>
<p>The daring bravo is equally adept in social situations and combat, with the right equipment to move fluidly from one to the other. Such adventurers are known as much for their flair and panache as their martial prowess, and the daring bravo's equipment is often ornately ornamented or personalized. This equipment package is good for a bard, fighter, rogue, swashbuckler, or vigilante. Certain cavaliers, investigators, skalds, or even paladins may also find it appealing. If the PC can cast spells, add a spell component pouch.</p>
<p><strong>Armor:</strong> <Link to="/rule/masterwork_a">masterwork</Link> <Link to="/eq-armor/chain_shirt">chain shirt</Link>.</p>
<p><strong>Weapons:</strong> <Link to="/eq-weapon/light_crossbow">Light crossbow</Link> with 10 bolts, <Link to="/rule/masterwork_w">masterwork</Link> <Link to="/eq-weapon/rapier">rapier</Link>, <Link to="/eq-weapon/sap">sap</Link>, <Link to="/eq-material/alchemical_silver">alchemical silver</Link> <Link to="/eq-weapon/dagger">dagger</Link>.</p>
<p><strong>Combat Gear:</strong> <Link to="/eq-weapon/acid">Acid</Link> (2), <Link to="/eq-misc/alchemists_kindness">alchemist's kindness</Link>, potions of <Link to="/spell/cure_light_wounds">cure light wounds</Link> (2), <Link to="/eq-misc/sunrod">sunrods</Link> (3).</p>
<p><strong>Other Gear:</strong> <Link to="/eq-misc/backpack">Backpack</Link>, <Link to="/eq-misc/bedroll">bedroll</Link>, <Link to="/eq-misc/belt_pouch">belt pouch</Link>, <Link to="/eq-misc/bottle_of_fine_wine">bottle of fine wine</Link>, <Link to="/eq-misc/chalk">chalk</Link> (5 pieces), <Link to="/eq-misc/courtiers_outfit">courtier's outfit</Link> with 50 gp in jewelry, <Link to="/eq-misc/flask">flask</Link>, <Link to="/eq-misc/flint_and_steel">flint and steel</Link>, <Link to="/eq-misc/grooming_kit">grooming kit</Link>, <Link to="/eq-misc/masterwork_musical_instrument">masterwork musical instrument</Link>, <Link to="/eq-misc/mess_kit">mess kit</Link>, <Link to="/eq-misc/mirror">mirror</Link>, <Link to="/eq-misc/perfume">perfume</Link> or <Link to="/eq-misc/cologne">cologne</Link>, <Link to="/eq-misc/sack">sack</Link>, <Link to="/eq-misc/signet_ring">signet ring</Link>, <Link to="/eq-misc/silk_rope_50_ft">silk rope (50 ft.)</Link>, <Link to="/eq-misc/trail_rations">trail rations</Link> (5 days), <Link to="/eq-misc/waterskin">waterskin</Link>, <Link to="/eq-misc/whetstone">whetstone</Link>, 5 gp.</p>
<p><strong>Total Weight:</strong> 76-1/2 lbs. (40-1/2 lbs. for a Small character).</p>
</>};
const _darklight_lantern = {title: "Darklight lantern", jsx: <><h2 id="eq-misc-darklight_lantern-darklight-lantern">Darklight lantern</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 111</Link><br/><strong>Price</strong> 20 gp; <strong>Weight</strong> 3 lbs.<br/><strong>Category</strong> Alchemical Tools</p>
<p>This lantern does not burn oil, but instead burns <Link to="/eq-weapon/shadowcloy_flask">shadowcloy</Link>. When shadowcloy is used as its fuel, this lantern creates a strange, hazy darkness that decreases the light level for 30 feet around it by one step. Unlike when shadowcloy is thrown at a single target, this haze does not decrease natural darkness to supernatural darkness. One flask of shadowcloy fuels a darklight lantern for 1 minute.</p>
</>};
const _darkwood_mwagni_harp = {title: "Darkwood Mwagni harp", jsx: <><h2 id="eq-misc-darkwood_mwagni_harp-darkwood-mwagni-harp">Darkwood Mwagni harp</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 20</Link><br/><strong>Price</strong> 130 gp; <strong>Weight</strong> 1-1/2 lb.<br/><strong>Category</strong> Tools</p>
<p>Musicians in the Mwangi Expanse make frequent use of carved harps strung with strings made from natural materials. These harps often feature ornately detailed soundboards and necks shaped like creatures that inhabit the region. Harps crafted from <Link to="/eq-material/darkwood">darkwood</Link> are very light compared to similar instruments, yet they retain the resonance and tonal quality demanded by the pickiest of musicians. A darkwood Mwangi harp is a <Link to="/eq-misc/masterwork_musical_instrument">masterwork musical instrument</Link> that grants you a +2 circumstance bonus on Perform checks when using it.</p>
</>};
const _darkwood_ancestry_plank = {title: "Darkwood ancestry plank", jsx: <><h2 id="eq-misc-darkwood_ancestry_plank-darkwood-ancestry-plank">Darkwood ancestry plank</h2>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest pg. 20</Link><br/><strong>Price</strong> 10 gp; <strong>Weight</strong> 1/2 lb.<br/><strong>Category</strong> Adventuring Gear</p>
<p>Ancestor worship is common among the peoples of the Mwangi Expanse, and many display wooden planks in their homes that contain depictions of enormous trees with the names of their ancestors carved onto branches. Ancestry planks made of <Link to="/eq-material/darkwood">darkwood</Link> are much lighter and smaller than their conventional counterparts, which make them appealing to Mwangi adventurers looking to honor their lineages while venturing away from home. Many from the Mwangi Expanse recognize the difficulty in obtaining darkwood and view those who carry darkwood ancestry planks with respect.</p>
</>};
const _dartboard_set = {title: "Dartboard set", jsx: <><h2 id="eq-misc-dartboard_set-dartboard-set">Dartboard set</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 92</Link><br/><strong>Price</strong> 5 sp; <strong>Weight</strong> 10 lbs.<br/><strong>Category</strong> Entertainment</p>
<p>This set includes a multicolored board and six brass-tipped darts. The board usually consists of a layer of soft wood or cork on a hardwood backing.</p>
</>};
const _darting_eye_concoction = {title: "Darting-eye concoction", jsx: <><h2 id="eq-misc-darting_eye_concoction-darting-eye-concoction">Darting-eye concoction</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 26</Link><br/><strong>Price</strong> 50 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Concoctions</p>
<p>This effervescent concoction improves your sensory reaction time, providing a +2 alchemical bonus on Perception checks. However, the mental hyperactivity it creates imparts a -1 penalty on your Will saving throws.</p>
</>};
const _dead_air_vial = {title: "Dead air vial", jsx: <><h2 id="eq-misc-dead_air_vial-dead-air-vial">Dead air vial</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements pg. 19</Link><br/><strong>Price</strong> 200 gp; <strong>Weight</strong> -<br/><strong>Category</strong> Alchemical Tools</p>
<p>Within this corked vial is a tiny sample of what is known as "dead air." Heavy, still, and of unknown origin, pockets of dead air becalm airships and smother crews in remote parts of the Plane of Air. When you open a dead air vial, invisible dead air fills a 20-foot-radius area centered on you. The affected area becomes devoid of breathable air. Creatures that breathe air must <Link to="/misc/hold_their_breath">hold their breath</Link> or <Link to="/rule/suffocate">suffocate</Link> in an area of dead air, though sound, fire, and other effects that rely on a stable atmosphere are unaffected. Undisturbed, the dead air dissipates in 1 minute. A moderate wind (11+ mph) disperses the dead air in 4 rounds; a strong wind (21+ mph) disperses the dead air in 1 round. This item can be crafted with a successful DC 25 Craft (alchemy) check.</p>
<p><strong>Construction:</strong> Craft (Alchemy) DC 25</p>
</>};
